                    <div className="w-7 h-7 rounded-lg flex items-center justify-center" style={{ backgroundColor: color + "20" }}>
                      <Icon size={14} weight="fill" style={{ color }} />
                    </div>
                  </div>
                  <p className="text-2xl font-bold text-gray-800 mb-1">{value}</p>
