// ─── Actions Menu ─────────────────────────────────────────────────────────────
function ActionsMenu({ field, onView }: { field: Field; onView: () => void }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  return (
    <div className="relative" ref={ref}>
      <button
        onClick={() => setOpen(o => !o)}
        className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors"
      >
        <DotsThree size={18} weight="bold" />
      </button>

      {open && (
        <div className="absolute right-0 top-8 w-44 bg-white rounded-xl shadow-xl border border-gray-100 py-1.5 z-20">
          <button
            onClick={() => { onView(); setOpen(false); }}
            className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-gray-700 hover:bg-gray-50 transition-colors"
          >
            <Eye size={13} className="text-gray-400" /> View Details
          </button>
          <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-gray-700 hover:bg-gray-50 transition-colors">
            <Phone size={13} className="text-gray-400" /> Call Vendor
          </button>
          <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-gray-700 hover:bg-gray-50 transition-colors">
            <Envelope size={13} className="text-gray-400" /> Email Vendor
          </button>

          <div className="border-t border-gray-100 my-1" />

          {field.status === "pending" && (
            <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-green-600 hover:bg-green-50 transition-colors font-medium">
              <CheckCircle size={13} /> Approve Field
            </button>
          )}
          {field.status === "active" && (
            <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-gray-600 hover:bg-gray-50 transition-colors">
              <XCircle size={13} /> Deactivate
            </button>
          )}
          {field.status === "inactive" && (
            <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-green-600 hover:bg-green-50 transition-colors">
              <CheckCircle size={13} /> Reactivate
            </button>
          )}
          {field.status === "suspended" && (
            <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-green-600 hover:bg-green-50 transition-colors">
              <ArrowsClockwise size={13} /> Reinstate
            </button>
          )}
          {field.status !== "suspended" && (
            <button className="flex items-center gap-2.5 w-full px-3 py-2 text-xs text-red-500 hover:bg-red-50 transition-colors">
              <Prohibit size={13} /> Suspend Field
            </button>
          )}
        </div>
      )}
    </div>
  );
}

// ─── Detail Panel ─────────────────────────────────────────────────────────────
const TOTAL_SLOTS = 17; // 6 AM – 10 PM (last slot starts at 10 PM)
const TODAY = new Date(2026, 2, 21); // Mar 21, 2026

/** Deterministic mock booked slots for a given field + date */
function getMockBookedSlots(field: Field, date: Date): Set<number> {
  if (field.status !== "active") return new Set();
  const day = date.getDay();
  const isWeekend = day === 0 || day === 6;
  const popularity = Math.min(Math.floor(field.totalBookings / 80), 8);
  const base = isWeekend ? popularity + 5 : popularity + 2;
  const count = Math.min(base, 13);
  const seed = (field.id.charCodeAt(4) || 3) + date.getDate() * 7 + date.getMonth() * 31;
  const booked = new Set<number>();
  for (let i = 0; booked.size < count; i++) {
    booked.add(((seed * (i + 3) * 7) + i * 13) % TOTAL_SLOTS);
    if (i > 200) break;
  }
  return booked;
}

/** Format a Date to display string */
function fmtDate(d: Date): string {
  return d.toLocaleDateString("en-IN", { weekday: "short", day: "numeric", month: "short", year: "numeric" });
}

/** Format a Date to a key string */
function dateKey(d: Date): string {
  return `${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;
}

function FieldDetailPanel({ field, onClose }: { field: Field; onClose: () => void }) {
  const [tab, setTab] = useState<"overview" | "schedule" | "analytics">("overview");
  const sc = STATUS_CONFIG[field.status];

  // Schedule state
  const [scheduleDate, setScheduleDate] = useState<Date>(new Date(TODAY));
  const [calOpen, setCalOpen]           = useState(false);
  const [calMonth, setCalMonth]         = useState(TODAY.getMonth());
  const [calYear, setCalYear]           = useState(TODAY.getFullYear());
  // blocked slots: dateKey -> Set of slot indices blocked by admin
  const [blockedMap, setBlockedMap]     = useState<Record<string, Set<number>>>({});

  const calRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    const h = (e: MouseEvent) => {
      if (calRef.current && !calRef.current.contains(e.target as Node)) setCalOpen(false);
    };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  const dk            = dateKey(scheduleDate);
  const bookedSlots   = getMockBookedSlots(field, scheduleDate);
  const blocked       = blockedMap[dk] ?? new Set<number>();

  function toggleBlock(slotIdx: number) {
    if (bookedSlots.has(slotIdx)) return; // can't block a booked slot
    setBlockedMap(prev => {
      const next = new Map(Object.entries(prev));
      const cur  = new Set(prev[dk] ?? []);
      if (cur.has(slotIdx)) cur.delete(slotIdx); else cur.add(slotIdx);
      return { ...prev, [dk]: cur };
    });
  }

  function blockAllAvailable() {
    setBlockedMap(prev => {
      const cur = new Set(prev[dk] ?? []);
      for (let i = 0; i < TOTAL_SLOTS; i++) {
        if (!bookedSlots.has(i)) cur.add(i);
      }
      return { ...prev, [dk]: cur };
    });
  }

  function unblockAll() {
    setBlockedMap(prev => ({ ...prev, [dk]: new Set() }));
  }

  function blockPeak() {
    // Peak = slots 11 onwards (5PM+)
    setBlockedMap(prev => {
      const cur = new Set(prev[dk] ?? []);
      for (let i = 11; i < TOTAL_SLOTS; i++) {
        if (!bookedSlots.has(i)) cur.add(i);
      }
      return { ...prev, [dk]: cur };
    });
  }

  function shiftDate(delta: number) {
    const d = new Date(scheduleDate);
    d.setDate(d.getDate() + delta);
    setScheduleDate(d);
    setCalMonth(d.getMonth());
    setCalYear(d.getFullYear());
  }

  const bookedCount    = bookedSlots.size;
  const blockedCount   = [...blocked].filter(i => !bookedSlots.has(i)).length;
  const availableCount = TOTAL_SLOTS - bookedCount - blockedCount;
  const occupancyPct   = Math.round((bookedCount / TOTAL_SLOTS) * 100);

  // Mini calendar helpers
  const monthNames = ["Jan","Feb","Mar","Apr","May","Jun","Jul","Aug","Sep","Oct","Nov","Dec"];
  const calDays: (Date | null)[] = [];
  const firstDay = new Date(calYear, calMonth, 1).getDay();
  const daysInMonth = new Date(calYear, calMonth + 1, 0).getDate();
  for (let i = 0; i < firstDay; i++) calDays.push(null);
  for (let d = 1; d <= daysInMonth; d++) calDays.push(new Date(calYear, calMonth, d));

  return (
    <div className="fixed right-0 top-0 bottom-0 w-[420px] bg-white shadow-2xl z-50 flex flex-col overflow-hidden border-l border-gray-100">

      {/* Header */}
      <div
        className="shrink-0 px-5 py-4 flex items-start justify-between"
        style={{ background: "linear-gradient(135deg,#8a9e60,#6e8245)" }}
      >
        <div className="flex-1 min-w-0 pr-3">
          <p className="text-white/60 text-[11px] font-medium mb-0.5">{field.id}</p>
          <h2 className="text-white font-bold text-base leading-tight truncate">{field.name}</h2>
          <p className="text-white/60 text-[11px] mt-0.5 flex items-center gap-1">
            <MapPin size={10} /> {field.location.address}, {field.location.city}
          </p>
          <div className="flex flex-wrap items-center gap-1.5 mt-2">
            <span className={`text-[10px] font-semibold px-2 py-0.5 rounded-full flex items-center gap-1 ${sc.color}`}>
              <span className={`w-1.5 h-1.5 rounded-full ${sc.dot}`} />
              {sc.label}
            </span>
            {field.sports.map(s => (
              <span key={s} className="text-[10px] bg-white/20 text-white px-2 py-0.5 rounded-full">{s}</span>
            ))}
          </div>
        </div>
        <button onClick={onClose} className="text-white/60 hover:text-white shrink-0 mt-0.5">
          <X size={20} />
        </button>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-gray-100 shrink-0 bg-white">
        {(["overview", "schedule", "analytics"] as const).map(t => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className={`flex-1 py-2.5 text-xs font-semibold capitalize transition-colors ${
              tab === t
                ? "border-b-2 border-[#8a9e60] text-[#8a9e60]"
                : "text-gray-400 hover:text-gray-600"
            }`}
          >
            {t}
          </button>
        ))}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4">

        {/* ── OVERVIEW TAB ── */}
        {tab === "overview" && (
          <>
            {/* Quick stats */}
            <div className="grid grid-cols-3 gap-2">
              <div className="bg-gray-50 rounded-xl p-3 text-center">
                <p className="text-lg font-bold text-gray-800">₹{field.pricePerHour}</p>
                <p className="text-[10px] text-gray-400">per hour</p>
              </div>
              <div className="bg-gray-50 rounded-xl p-3 text-center">
                <p className="text-lg font-bold text-gray-800">{field.capacity}</p>
                <p className="text-[10px] text-gray-400">capacity</p>
              </div>
              <div className="bg-gray-50 rounded-xl p-3 text-center">
                <div className="flex items-center justify-center gap-0.5">
                  <p className="text-lg font-bold text-gray-800">{field.rating > 0 ? field.rating : "—"}</p>
                  {field.rating > 0 && <Star size={11} weight="fill" className="text-amber-400 mb-0.5" />}
                </div>
                <p className="text-[10px] text-gray-400">{field.totalReviews > 0 ? `${field.totalReviews} reviews` : "No reviews"}</p>
              </div>
            </div>

            {/* About */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">About</p>
              <p className="text-xs text-gray-600 leading-relaxed">{field.description}</p>
            </div>

            {/* Field Details */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">Field Details</p>
              <div className="space-y-2.5">
                {[
                  ["Surface",          field.surface],
                  ["Size / Format",    field.size],
                  ["Capacity",         `${field.capacity} players`],
                  ["Operating Hours",  field.operatingHours],
                  ["Standard Price",   `₹${field.pricePerHour} / hr`],
                  ["Peak Price",       `₹${field.peakPricePerHour} / hr`],
                  ["Listed Since",     field.listedAt],
                ].map(([label, value]) => (
                  <div key={label} className="flex items-center justify-between text-xs">
                    <span className="text-gray-400">{label}</span>
                    <span className="font-medium text-gray-700 text-right max-w-[55%]">{value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Amenities */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">Amenities</p>
              <div className="flex flex-wrap gap-1.5">
                {field.amenities.map(a => (
                  <span key={a} className="text-[11px] bg-gray-100 text-gray-600 px-2.5 py-1 rounded-full font-medium">{a}</span>
                ))}
              </div>
            </div>

            {/* Vendor */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">Vendor</p>
              <div className="bg-gray-50 rounded-xl p-3.5">
                <div className="flex items-center gap-3 mb-3">
                  <div
                    className="w-9 h-9 rounded-full flex items-center justify-center text-white text-[11px] font-bold shrink-0"
                    style={{ backgroundColor: "#8a9e60" }}
                  >
                    {field.vendor.avatar}
                  </div>
                  <div>
                    <p className="text-sm font-semibold text-gray-800">{field.vendor.name}</p>
                    <p className="text-[11px] text-gray-400">{field.vendor.email}</p>
                    <p className="text-[11px] text-gray-400">{field.vendor.phone}</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <a
                    href={`tel:${field.vendor.phone}`}
                    className="flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-xs font-medium bg-white border border-gray-200 text-gray-700 hover:bg-gray-50 transition-colors"
                  >
                    <Phone size={13} /> Call
                  </a>
                  <button
                    className="flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-xs font-medium text-white hover:opacity-90 transition-opacity"
                    style={{ backgroundColor: "#8a9e60" }}
                  >
                    <Envelope size={13} /> Email
                  </button>
                </div>
              </div>
            </div>
          </>
        )}

        {/* ── SCHEDULE TAB ── */}
        {tab === "schedule" && (
          <>
            {/* ── Date navigation ── */}
            <div className="flex items-center gap-2" ref={calRef}>
              <button
                onClick={() => shiftDate(-1)}
                className="p-1.5 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors shrink-0"
              >
                <CaretLeft size={14} weight="bold" />
              </button>

              {/* Date button — opens mini calendar */}
              <button
                onClick={() => setCalOpen(o => !o)}
                className="flex-1 flex items-center justify-center gap-2 py-2 rounded-xl border border-gray-200 bg-white hover:bg-gray-50 text-xs font-semibold text-gray-700 transition-colors relative"
              >
                <CaretDown size={12} className="text-gray-400" />
                {fmtDate(scheduleDate)}
                {dateKey(scheduleDate) === dateKey(TODAY) && (
                  <span className="text-[10px] font-bold px-1.5 py-0.5 rounded-full text-white ml-1" style={{ backgroundColor: "#8a9e60" }}>
                    Today
                  </span>
                )}
              </button>

              <button
                onClick={() => shiftDate(1)}
                className="p-1.5 rounded-lg bg-gray-100 hover:bg-gray-200 text-gray-600 transition-colors shrink-0"
              >
                <CaretRight size={14} weight="bold" />
              </button>

              {/* Mini calendar dropdown */}
              {calOpen && (
                <div className="absolute left-4 right-4 top-auto z-30 mt-1 bg-white rounded-2xl shadow-2xl border border-gray-100 p-3"
                  style={{ top: "auto" }}
                >
                  {/* Month nav */}
                  <div className="flex items-center justify-between mb-2">
                    <button
                      onClick={() => { if (calMonth === 0) { setCalMonth(11); setCalYear(y => y - 1); } else setCalMonth(m => m - 1); }}
                      className="p-1 rounded-lg hover:bg-gray-100 text-gray-500"
                    >
                      <CaretLeft size={13} weight="bold" />
                    </button>
                    <p className="text-xs font-bold text-gray-700">{monthNames[calMonth]} {calYear}</p>
                    <button
                      onClick={() => { if (calMonth === 11) { setCalMonth(0); setCalYear(y => y + 1); } else setCalMonth(m => m + 1); }}
                      className="p-1 rounded-lg hover:bg-gray-100 text-gray-500"
                    >
                      <CaretRight size={13} weight="bold" />
                    </button>
                  </div>

                  {/* Day headers */}
                  <div className="grid grid-cols-7 mb-1">
                    {["S","M","T","W","T","F","S"].map((d, i) => (
                      <div key={i} className="text-center text-[10px] font-bold text-gray-300 py-1">{d}</div>
                    ))}
                  </div>

                  {/* Days grid */}
                  <div className="grid grid-cols-7 gap-0.5">
                    {calDays.map((d, i) => {
                      if (!d) return <div key={`e${i}`} />;
                      const isToday    = dateKey(d) === dateKey(TODAY);
                      const isSel      = dateKey(d) === dateKey(scheduleDate);
                      const isPast     = d < new Date(TODAY.getFullYear(), TODAY.getMonth(), TODAY.getDate());
                      const hasBooking = getMockBookedSlots(field, d).size > 0;
                      return (
                        <button
                          key={i}
                          onClick={() => { setScheduleDate(new Date(d)); setCalOpen(false); }}
                          className={`relative text-center text-[11px] py-1.5 rounded-lg font-medium transition-colors ${
                            isSel
                              ? "text-white font-bold"
                              : isToday
                              ? "font-bold border"
                              : isPast
                              ? "text-gray-300 hover:bg-gray-50"
                              : "text-gray-600 hover:bg-gray-100"
                          }`}
                          style={
                            isSel
                              ? { backgroundColor: "#8a9e60" }
                              : isToday
                              ? { borderColor: "#8a9e60", color: "#8a9e60" }
                              : {}
                          }
                        >
                          {d.getDate()}
                          {hasBooking && !isSel && (
                            <span
                              className="absolute bottom-0.5 left-1/2 -translate-x-1/2 w-1 h-1 rounded-full"
                              style={{ backgroundColor: isSel ? "white" : "#8a9e60" }}
                            />
                          )}
                        </button>
                      );
                    })}
                  </div>

                  <button
                    onClick={() => { setScheduleDate(new Date(TODAY)); setCalMonth(TODAY.getMonth()); setCalYear(TODAY.getFullYear()); setCalOpen(false); }}
                    className="mt-2 w-full text-center text-[11px] font-semibold py-1.5 rounded-lg hover:bg-gray-50 transition-colors"
                    style={{ color: "#8a9e60" }}
                  >
                    Jump to Today
                  </button>
                </div>
              )}
            </div>

            {/* ── Field not bookable ── */}
            {field.status === "maintenance" ? (
              <div className="bg-blue-50 border border-blue-100 rounded-xl p-5 text-center">
                <Wrench size={26} className="text-blue-300 mx-auto mb-2" />
                <p className="text-sm font-semibold text-blue-600">Under Maintenance</p>
                <p className="text-xs text-blue-400 mt-1">No slots available on any date</p>
              </div>
            ) : field.status !== "active" ? (
              <div className="bg-gray-50 border border-gray-100 rounded-xl p-5 text-center">
                <XCircle size={26} className="text-gray-300 mx-auto mb-2" />
                <p className="text-sm font-semibold text-gray-500">Field Not Active</p>
                <p className="text-xs text-gray-400 mt-1">Activate the field to manage slots</p>
              </div>
            ) : (
              <>
                {/* ── Legend ── */}
                <div className="flex items-center gap-3 text-[11px] text-gray-500 flex-wrap">
                  <span className="flex items-center gap-1.5">
                    <span className="w-3 h-3 rounded" style={{ backgroundColor: "#8a9e60" }} /> Booked
                  </span>
                  <span className="flex items-center gap-1.5">
                    <span className="w-3 h-3 rounded bg-red-100 border border-red-200" /> Blocked
                  </span>
                  <span className="flex items-center gap-1.5">
                    <span className="w-3 h-3 rounded bg-gray-100 border border-gray-200" /> Available
                  </span>
                  <span className="text-[10px] text-gray-400 ml-auto">Click to block/unblock</span>
                </div>

                {/* ── Slot grid ── */}
                <div className="grid grid-cols-4 gap-1.5">
                  {Array.from({ length: TOTAL_SLOTS }, (_, i) => {
                    const hour     = 6 + i;
                    const isBooked = bookedSlots.has(i);
                    const isBlocked = !isBooked && blocked.has(i);
                    const h    = hour > 12 ? hour - 12 : hour === 12 ? 12 : hour;
                    const ampm = hour >= 12 ? "PM" : "AM";
                    const isPeak = hour >= 17;

                    return (
                      <button
                        key={i}
                        disabled={isBooked}
                        onClick={() => toggleBlock(i)}
                        className={`rounded-xl py-2.5 text-center flex flex-col items-center gap-0.5 transition-all ${
                          isBooked
                            ? "cursor-default"
                            : isBlocked
                            ? "bg-red-50 border border-red-200 hover:bg-red-100"
                            : "bg-gray-50 border border-gray-100 hover:border-gray-300 hover:bg-white"
                        }`}
                        style={isBooked ? { backgroundColor: "#8a9e60" } : {}}
                      >
                        <span className={`text-[10px] font-bold ${
                          isBooked ? "text-white" : isBlocked ? "text-red-500" : "text-gray-500"
                        }`}>
                          {h}{ampm}
                        </span>
                        {isPeak && !isBooked && (
                          <span className={`text-[8px] font-semibold ${isBlocked ? "text-red-400" : "text-amber-500"}`}>
                            PEAK
                          </span>
                        )}
                        {isBooked && (
                          <CheckCircle size={10} className="text-white/70" weight="fill" />
                        )}
                        {isBlocked && (
                          <LockSimple size={10} className="text-red-400" weight="fill" />
                        )}
                      </button>
                    );
                  })}
                </div>

                {/* ── Quick actions ── */}
                <div className="flex gap-2 flex-wrap">
                  <button
                    onClick={blockAllAvailable}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-red-50 text-red-500 text-[11px] font-semibold hover:bg-red-100 transition-colors"
                  >
                    <LockSimple size={12} weight="fill" /> Block All
                  </button>
                  <button
                    onClick={blockPeak}
                    className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-amber-50 text-amber-600 text-[11px] font-semibold hover:bg-amber-100 transition-colors"
                  >
                    <LockSimple size={12} /> Block Peak (5PM+)
                  </button>
                  {blockedCount > 0 && (
                    <button
                      onClick={unblockAll}
                      className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-green-50 text-green-600 text-[11px] font-semibold hover:bg-green-100 transition-colors"
                    >
                      <LockSimpleOpen size={12} /> Unblock All
                    </button>
                  )}
                </div>

                {/* ── Day summary ── */}
                <div className="bg-gray-50 rounded-xl p-3.5">
                  <p className="text-xs font-semibold text-gray-700 mb-3">
                    {fmtDate(scheduleDate)} — Summary
                  </p>
                  <div className="grid grid-cols-4 gap-2 text-center mb-3">
                    <div>
                      <p className="text-base font-bold text-gray-800">{bookedCount}</p>
                      <p className="text-[10px] text-gray-400">Booked</p>
                    </div>
                    <div>
                      <p className="text-base font-bold text-red-500">{blockedCount}</p>
                      <p className="text-[10px] text-gray-400">Blocked</p>
                    </div>
                    <div>
                      <p className="text-base font-bold text-gray-600">{availableCount}</p>
                      <p className="text-[10px] text-gray-400">Available</p>
                    </div>
                    <div>
                      <p className="text-base font-bold" style={{ color: "#8a9e60" }}>{occupancyPct}%</p>
                      <p className="text-[10px] text-gray-400">Booked%</p>
                    </div>
                  </div>
                  {/* Stacked bar */}
                  <div className="flex rounded-full overflow-hidden h-2 bg-gray-200">
                    <div style={{ width: `${occupancyPct}%`, backgroundColor: "#8a9e60" }} />
                    <div style={{ width: `${Math.round((blockedCount / TOTAL_SLOTS) * 100)}%`, backgroundColor: "#fca5a5" }} />
                  </div>
                  <div className="flex justify-between text-[9px] text-gray-400 mt-1">
                    <span>Booked</span>
                    <span>Blocked</span>
                    <span>Available</span>
                  </div>
                </div>

                {/* ── Pricing note ── */}
                <div className="bg-amber-50 rounded-xl p-3 border border-amber-100">
                  <p className="text-[11px] font-bold text-amber-700 mb-1.5">Pricing Tiers</p>
                  <div className="space-y-1 text-xs text-amber-700">
                    <div className="flex justify-between">
                      <span className="text-amber-600">Standard (6AM – 5PM)</span>
                      <span className="font-semibold">₹{field.pricePerHour}/hr</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-amber-600">Peak (5PM – close)</span>
                      <span className="font-semibold">₹{field.peakPricePerHour}/hr</span>
                    </div>
                  </div>
                </div>
              </>
            )}
          </>
        )}

        {/* ── ANALYTICS TAB ── */}
        {tab === "analytics" && (
          <>
            {/* Key metrics */}
            <div className="grid grid-cols-2 gap-2.5">
              {[
                { label: "Total Bookings", value: field.totalBookings.toLocaleString(), sub: "all time" },
                { label: "Total Revenue",  value: field.totalRevenue > 0 ? `₹${(field.totalRevenue / 1000).toFixed(0)}K` : "—", sub: "all time" },
                { label: "Avg. Rating",    value: field.rating > 0 ? `${field.rating} ★` : "—", sub: `${field.totalReviews} reviews` },
                {
                  label: "Avg / Booking",
                  value: field.totalBookings > 0 ? `₹${Math.round(field.totalRevenue / field.totalBookings).toLocaleString()}` : "—",
                  sub: "revenue per booking",
                },
              ].map(({ label, value, sub }) => (
                <div key={label} className="bg-gray-50 rounded-xl p-3.5">
                  <p className="text-[11px] text-gray-400 mb-1">{label}</p>
                  <p className="text-xl font-bold text-gray-800">{value}</p>
                  <p className="text-[10px] text-gray-400 mt-0.5">{sub}</p>
                </div>
              ))}
            </div>

            {/* Weekly occupancy bar chart */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-3">Weekly Occupancy</p>
              {field.totalBookings === 0 ? (
                <div className="bg-gray-50 rounded-xl p-6 text-center text-xs text-gray-400">
                  No data — field not yet live
                </div>
              ) : (
                <div className="bg-gray-50 rounded-xl p-4">
                  <div className="flex items-end gap-2 h-28">
                    {[
                      { day: "Mon", pct: 68 },
                      { day: "Tue", pct: 55 },
                      { day: "Wed", pct: 80 },
                      { day: "Thu", pct: 62 },
                      { day: "Fri", pct: 91 },
                      { day: "Sat", pct: 96 },
                      { day: "Sun", pct: 89 },
                    ].map(({ day, pct }) => (
                      <div key={day} className="flex-1 flex flex-col items-center gap-1">
                        <p className="text-[9px] text-gray-500 font-medium">{pct}%</p>
                        <div
                          className="w-full rounded-t"
                          style={{ height: `${(pct / 100) * 72}px`, backgroundColor: "#8a9e60", opacity: 0.85 }}
                        />
                        <p className="text-[9px] text-gray-400">{day}</p>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>

            {/* Revenue breakdown */}
            <div>
              <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-2">Revenue Breakdown</p>
              <div className="space-y-2.5">
                {[
                  [
                    "Est. This Month",
                    field.totalBookings > 0
                      ? `₹${((field.pricePerHour * field.todayBookings * 21) / 1000).toFixed(1)}K`
                      : "—",
                  ],
                  [
                    "Platform Fee (10%)",
                    field.totalRevenue > 0
                      ? `₹${(field.totalRevenue * 0.1 / 1000).toFixed(1)}K`
                      : "—",
                  ],
                  [
                    "Vendor Payout (90%)",
                    field.totalRevenue > 0
                      ? `₹${(field.totalRevenue * 0.9 / 1000).toFixed(0)}K`
                      : "—",
                  ],
                ].map(([label, value]) => (
                  <div key={label} className="flex items-center justify-between text-xs">
                    <span className="text-gray-400">{label}</span>
                    <span className="font-semibold text-gray-700">{value}</span>
                  </div>
                ))}
              </div>
            </div>

            {/* Performance badge */}
            {field.totalBookings > 500 && (
              <div
                className="rounded-xl p-3.5 flex items-center gap-3"
                style={{ background: "linear-gradient(135deg,#8a9e6015,#6e824510)" }}
              >
                <Star size={24} weight="fill" style={{ color: "#8a9e60" }} className="shrink-0" />
                <div>
                  <p className="text-xs font-bold text-gray-700">Top Performing Field</p>
                  <p className="text-[11px] text-gray-500">Over 500 bookings — top 20% on the platform</p>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Admin Actions */}
      <div className="shrink-0 border-t border-gray-100 p-4">
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2.5">Admin Actions</p>
        <div className="space-y-2">
          {field.status === "pending" && (
            <button
              className="w-full py-2.5 rounded-xl text-sm font-semibold text-white hover:opacity-90 flex items-center justify-center gap-2 transition-opacity"
              style={{ backgroundColor: "#8a9e60" }}
            >
              <CheckCircle size={16} weight="fill" /> Approve Field
            </button>
          )}
          {field.status === "inactive" && (
            <button
              className="w-full py-2.5 rounded-xl text-sm font-semibold text-white hover:opacity-90 flex items-center justify-center gap-2 transition-opacity"
              style={{ backgroundColor: "#8a9e60" }}
            >
              <CheckCircle size={16} weight="fill" /> Reactivate Field
            </button>
          )}
          {field.status === "suspended" && (
            <button
              className="w-full py-2.5 rounded-xl text-sm font-semibold text-white hover:opacity-90 flex items-center justify-center gap-2 transition-opacity"
              style={{ backgroundColor: "#8a9e60" }}
            >
              <ArrowsClockwise size={16} /> Reinstate Field
            </button>
          )}
          {field.status === "active" && (
            <button className="w-full py-2.5 rounded-xl text-sm font-semibold bg-gray-100 text-gray-700 hover:bg-gray-200 flex items-center justify-center gap-2 transition-colors">
              <XCircle size={16} /> Deactivate Field
            </button>
          )}
          {(field.status === "active" || field.status === "inactive") && (
            <button className="w-full py-2.5 rounded-xl text-sm font-semibold bg-blue-50 text-blue-600 hover:bg-blue-100 flex items-center justify-center gap-2 transition-colors">
              <Wrench size={16} /> Mark as Maintenance
            </button>
          )}
          {field.status !== "suspended" && (
            <button className="w-full py-2.5 rounded-xl text-sm font-semibold bg-red-50 text-red-500 hover:bg-red-100 flex items-center justify-center gap-2 transition-colors">
              <Prohibit size={16} /> Suspend Field
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

// ─── Main Page ────────────────────────────────────────────────────────────────
export default function FieldsPage() {
  const [search, setSearch]       = useState("");
  const [statusTab, setStatusTab] = useState("all");
  const [sportFilter, setSportFilter] = useState("All");
  const [cityFilter, setCityFilter]   = useState("All");
  const [sportOpen, setSportOpen] = useState(false);
  const [cityOpen, setCityOpen]   = useState(false);
  const [selected, setSelected]   = useState<Field | null>(null);

  // Onboard modal state
  const [showOnboard, setShowOnboard] = useState(false);
  const [onboardStep, setOnboardStep] = useState(1);
  const [formData, setFormData]       = useState<FormData>({ ...INIT_FORM });

  const setField = <K extends keyof FormData>(key: K, val: FormData[K]) =>
    setFormData(p => ({ ...p, [key]: val }));
  const toggleArr = (key: "sports" | "facilities", val: string) =>
    setFormData(p => {
      const arr = p[key] as string[];
      return { ...p, [key]: arr.includes(val) ? arr.filter(x => x !== val) : [...arr, val] };
    });
  const closeOnboard = () => { setShowOnboard(false); setOnboardStep(1); setFormData({ ...INIT_FORM }); };

  const sportRef = useRef<HTMLDivElement>(null);
  const cityRef  = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (sportRef.current && !sportRef.current.contains(e.target as Node)) setSportOpen(false);
      if (cityRef.current  && !cityRef.current.contains(e.target as Node))  setCityOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  // Derived counts
  const total       = fields.length;
  const activeCount = fields.filter(f => f.status === "active").length;
  const inactiveCount  = fields.filter(f => f.status === "inactive").length;
  const pendingCount   = fields.filter(f => f.status === "pending").length;
  const maintCount     = fields.filter(f => f.status === "maintenance").length;
  const suspendedCount = fields.filter(f => f.status === "suspended").length;

  const allSports = ["All", ...Array.from(new Set(fields.flatMap(f => f.sports)))];
  const allCities = ["All", ...Array.from(new Set(fields.map(f => f.location.city)))];

  const filtered = fields.filter(f => {
    const q = search.toLowerCase();
    const matchSearch = !q ||
      f.name.toLowerCase().includes(q) ||
      f.vendor.name.toLowerCase().includes(q) ||
      f.location.city.toLowerCase().includes(q) ||
      f.id.toLowerCase().includes(q);
    const matchStatus = statusTab === "all" || f.status === statusTab;
    const matchSport  = sportFilter === "All" || f.sports.includes(sportFilter);
    const matchCity   = cityFilter === "All"  || f.location.city === cityFilter;
    return matchSearch && matchStatus && matchSport && matchCity;
  });

  const STATUS_TABS = [
    { key: "all",         label: "All",         count: total        },
    { key: "active",      label: "Active",      count: activeCount  },
    { key: "inactive",    label: "Inactive",    count: inactiveCount},
    { key: "pending",     label: "Pending",     count: pendingCount },
    { key: "maintenance", label: "Maintenance", count: maintCount   },
    { key: "suspended",   label: "Suspended",   count: suspendedCount },
  ];

  const STAT_CARDS = [
    { label: "Total Fields",     value: total,        sub: "on platform",        color: "#8a9e60", Icon: MapPin        },
    { label: "Active Today",     value: activeCount,  sub: "accepting bookings", color: "#22c55e", Icon: CheckCircle   },
    { label: "Inactive",         value: inactiveCount,sub: "not accepting",      color: "#9ca3af", Icon: XCircle       },
    { label: "Pending Approval", value: pendingCount, sub: "awaiting review",    color: "#f59e0b", Icon: ClockCountdown},
    { label: "Maintenance",      value: maintCount,   sub: "temporarily closed", color: "#3b82f6", Icon: Wrench        },
  ];

  return (
    <div className="h-full flex flex-col overflow-hidden">

      {/* Stat cards + filters */}
      <div className="p-6 pb-0 shrink-0">

        {/* Stat cards */}
        <div className="grid grid-cols-5 gap-4 mb-5">
          {STAT_CARDS.map(({ label, value, sub, color, Icon }) => (
            <div key={label} className="bg-white rounded-2xl p-4 shadow-sm border border-gray-100">
              <div className="flex items-center justify-between mb-3">
                <span className="text-xs font-semibold text-gray-500 leading-tight">{label}</span>
                <div className="w-8 h-8 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: color + "18" }}>
                  <Icon size={16} weight="fill" style={{ color }} />
                </div>
              </div>
              <p className="text-2xl font-bold text-gray-800">{value}</p>
              <p className="text-xs text-gray-400 mt-0.5">{sub}</p>
            </div>
          ))}
        </div>

        {/* Filter bar */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 mb-4">
          <div className="flex items-center gap-3 flex-wrap">

            {/* Search */}
            <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-xl px-3 py-2 w-64">
              <MagnifyingGlass size={14} className="text-gray-400 shrink-0" />
              <input
                value={search}
                onChange={e => setSearch(e.target.value)}
                placeholder="Search fields, vendors, cities..."
                className="bg-transparent text-gray-700 placeholder-gray-400 text-xs flex-1 outline-none"
              />
            </div>

            {/* Sport filter */}
            <div className="relative" ref={sportRef}>
              <button
                onClick={() => setSportOpen(o => !o)}
                className="flex items-center gap-2 border border-gray-200 rounded-xl px-3 py-2 text-xs text-gray-600 bg-white hover:bg-gray-50 transition-colors"
              >
                <Funnel size={13} className="text-gray-400" />
                Sport: <span className="font-medium">{sportFilter}</span>
                <CaretDown size={11} className="text-gray-400" />
              </button>
              {sportOpen && (
                <div className="absolute top-10 left-0 bg-white border border-gray-100 rounded-xl shadow-xl py-1.5 z-10 min-w-[150px]">
                  {allSports.map(s => (
                    <button
                      key={s}
                      onClick={() => { setSportFilter(s); setSportOpen(false); }}
                      className={`w-full text-left px-3 py-2 text-xs hover:bg-gray-50 transition-colors ${
                        sportFilter === s ? "font-semibold" : "text-gray-700"
                      }`}
                      style={sportFilter === s ? { color: "#8a9e60" } : {}}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* City filter */}
            <div className="relative" ref={cityRef}>
              <button
                onClick={() => setCityOpen(o => !o)}
                className="flex items-center gap-2 border border-gray-200 rounded-xl px-3 py-2 text-xs text-gray-600 bg-white hover:bg-gray-50 transition-colors"
              >
                <MapPin size={13} className="text-gray-400" />
                City: <span className="font-medium">{cityFilter}</span>
                <CaretDown size={11} className="text-gray-400" />
              </button>
              {cityOpen && (
                <div className="absolute top-10 left-0 bg-white border border-gray-100 rounded-xl shadow-xl py-1.5 z-10 min-w-[150px]">
                  {allCities.map(c => (
                    <button
                      key={c}
                      onClick={() => { setCityFilter(c); setCityOpen(false); }}
                      className={`w-full text-left px-3 py-2 text-xs hover:bg-gray-50 transition-colors ${
                        cityFilter === c ? "font-semibold" : "text-gray-700"
                      }`}
                      style={cityFilter === c ? { color: "#8a9e60" } : {}}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Pending badge */}
            {pendingCount > 0 && (
              <div className="ml-auto flex items-center gap-1.5 bg-amber-50 border border-amber-200 rounded-xl px-3 py-2 text-xs font-semibold text-amber-700">
                <ClockCountdown size={13} weight="fill" />
                {pendingCount} field{pendingCount > 1 ? "s" : ""} awaiting approval
              </div>
            )}

            {/* Onboard Field Button */}
            <button onClick={() => setShowOnboard(true)}
              className={`${pendingCount > 0 ? "" : "ml-auto"} flex items-center gap-2 px-4 py-2 text-sm font-semibold text-white rounded-lg transition-opacity hover:opacity-90 shrink-0`}
              style={{ backgroundColor: "#8a9e60" }}>
              <Plus size={16} weight="bold" />
              Onboard Field
            </button>
          </div>

          {/* Status tabs */}
          <div className="flex gap-1.5 mt-3 flex-wrap">
            {STATUS_TABS.map(t => (
              <button
                key={t.key}
                onClick={() => setStatusTab(t.key)}
                className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-colors flex items-center gap-1.5 ${
                  statusTab === t.key ? "text-white" : "bg-gray-50 text-gray-500 hover:bg-gray-100"
                }`}
                style={statusTab === t.key ? { backgroundColor: "#8a9e60" } : {}}
              >
                {t.label}
                <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-semibold ${
                  statusTab === t.key ? "bg-white/20 text-white" : "bg-gray-200 text-gray-500"
                }`}>
                  {t.count}
                </span>
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="flex-1 overflow-hidden px-6 pb-6">
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm h-full flex flex-col overflow-hidden">
          <div className="overflow-x-auto overflow-y-auto flex-1">
            <table className="w-full">
              <thead className="bg-gray-50/80 sticky top-0 z-10">
                <tr>
                  {["Field", "Vendor", "Status", "Price / hr", "Today's Slots", "Rating", "Bookings", ""].map(h => (
                    <th
                      key={h}
                      className="text-left px-4 py-3 text-[11px] font-bold text-gray-400 uppercase tracking-wider whitespace-nowrap"
                    >
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>

              <tbody className="divide-y divide-gray-50">
                {filtered.map(field => {
                  const sc = STATUS_CONFIG[field.status];
                  const isSelected = selected?.id === field.id;
                  return (
                    <tr
                      key={field.id}
                      onClick={() => setSelected(field)}
                      className={`hover:bg-gray-50/60 transition-colors cursor-pointer ${
                        isSelected ? "bg-[#8a9e60]/5" : ""
                      }`}
                    >
                      {/* Field */}
                      <td className="px-4 py-3.5">
                        <div>
                          <div className="flex items-center gap-2 flex-wrap">
                            <p className="font-semibold text-gray-800 text-sm">{field.name}</p>
                            {field.sports.map(s => (
                              <span key={s} className="text-[10px] bg-gray-100 text-gray-500 px-1.5 py-0.5 rounded-full font-medium">{s}</span>
                            ))}
                          </div>
                          <p className="text-[11px] text-gray-400 mt-0.5 flex items-center gap-1">
                            <MapPin size={10} /> {field.location.address}, {field.location.city}
                          </p>
                          <p className="text-[10px] text-gray-300 mt-0.5">{field.id} · {field.surface} · {field.size}</p>
                        </div>
                      </td>

                      {/* Vendor */}
                      <td className="px-4 py-3.5">
                        <div className="flex items-center gap-2">
                          <div
                            className="w-7 h-7 rounded-full flex items-center justify-center text-white text-[10px] font-bold shrink-0"
                            style={{ backgroundColor: "#8a9e60" }}
                          >
                            {field.vendor.avatar}
                          </div>
                          <div>
                            <p className="text-xs font-medium text-gray-700 whitespace-nowrap">{field.vendor.name}</p>
                            <p className="text-[10px] text-gray-400">{field.location.city}</p>
                          </div>
                        </div>
                      </td>

                      {/* Status */}
                      <td className="px-4 py-3.5">
                        <span className={`inline-flex items-center gap-1.5 text-[11px] font-semibold px-2.5 py-1 rounded-full whitespace-nowrap ${sc.color}`}>
                          <span className={`w-1.5 h-1.5 rounded-full shrink-0 ${sc.dot}`} />
                          {sc.label}
                        </span>
                      </td>

                      {/* Price */}
                      <td className="px-4 py-3.5">
                        <p className="text-sm font-bold text-gray-800">₹{field.pricePerHour}</p>
                        <p className="text-[10px] text-gray-400">Peak: ₹{field.peakPricePerHour}</p>
                      </td>

                      {/* Today's Slots */}
                      <td className="px-4 py-3.5">
                        {field.status === "active" ? (
                          <div>
                            <p className="text-xs font-semibold text-gray-700">{field.todayBookings} / 17 booked</p>
                            <div className="w-24 bg-gray-100 rounded-full h-1.5 mt-1.5">
                              <div
                                className="h-1.5 rounded-full"
                                style={{ width: `${(field.todayBookings / 17) * 100}%`, backgroundColor: "#8a9e60" }}
                              />
                            </div>
                          </div>
                        ) : (
                          <span className="text-xs text-gray-300">—</span>
                        )}
                      </td>

                      {/* Rating */}
                      <td className="px-4 py-3.5">
                        {field.rating > 0 ? (
                          <div>
                            <div className="flex items-center gap-1">
                              <Star size={13} weight="fill" className="text-amber-400" />
                              <span className="text-sm font-bold text-gray-800">{field.rating}</span>
                            </div>
                            <p className="text-[10px] text-gray-400">{field.totalReviews} reviews</p>
                          </div>
                        ) : (
                          <span className="text-xs text-gray-300">No reviews</span>
                        )}
                      </td>

                      {/* Bookings */}
                      <td className="px-4 py-3.5">
                        <p className="text-sm font-bold text-gray-800">{field.totalBookings.toLocaleString()}</p>
                        <p className="text-[10px] text-gray-400">
                          {field.totalRevenue > 0 ? `₹${(field.totalRevenue / 1000).toFixed(0)}K rev.` : "No revenue yet"}
                        </p>
                      </td>

                      {/* Actions */}
                      <td className="px-4 py-3.5" onClick={e => e.stopPropagation()}>
                        <ActionsMenu field={field} onView={() => setSelected(field)} />
                      </td>
                    </tr>
                  );
                })}

                {filtered.length === 0 && (
                  <tr>
                    <td colSpan={8} className="py-20 text-center">
                      <Buildings size={32} className="text-gray-200 mx-auto mb-3" />
                      <p className="text-sm text-gray-400">No fields match your filters</p>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>

          {/* Footer */}
          <div className="shrink-0 border-t border-gray-100 px-4 py-3 flex items-center justify-between">
            <p className="text-xs text-gray-400">
              Showing <span className="font-semibold text-gray-600">{filtered.length}</span> of {total} fields
            </p>
            <div className="flex items-center gap-4 text-xs text-gray-400">
              {pendingCount > 0 && (
                <span className="flex items-center gap-1.5 text-amber-600 font-medium">
                  <ClockCountdown size={12} weight="fill" />
                  {pendingCount} pending approval
                </span>
              )}
              {suspendedCount > 0 && (
                <span className="flex items-center gap-1.5 text-red-500 font-medium">
                  <Prohibit size={12} />
                  {suspendedCount} suspended
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* ═══════════════════════════════════════════════════════════════════════
          ONBOARD FIELD MODAL
      ═══════════════════════════════════════════════════════════════════════ */}
      {showOnboard && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ backgroundColor: "rgba(0,0,0,0.55)", backdropFilter: "blur(4px)" }}>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[92vh] flex flex-col overflow-hidden">
            
            {/* Modal Header */}
            <div className="px-7 pt-6 pb-4 border-b border-gray-100 shrink-0">
              <div className="flex items-start justify-between mb-5">
                <div>
                  <h2 className="text-xl font-bold text-gray-900">Onboard New Field</h2>
                  <p className="text-xs text-gray-400 mt-0.5">Step {onboardStep} of {ONBOARD_STEPS.length} — {ONBOARD_STEPS[onboardStep - 1]}</p>
                </div>
                <button onClick={closeOnboard} className="text-gray-400 hover:text-gray-600 mt-1"><X size={20} /></button>
              </div>
              {/* Step indicator */}
              <div className="flex items-center">
                {ONBOARD_STEPS.map((label, i) => {
                  const n = i + 1; const done = n < onboardStep; const active = n === onboardStep;
                  return (
                    <div key={n} className="flex items-center flex-1 last:flex-none">
                      <div className="flex flex-col items-center gap-1 shrink-0">
                        <div className="w-7 h-7 rounded-full text-xs font-bold flex items-center justify-center transition-all"
                          style={{ backgroundColor: done || active ? "#8a9e60" : "#f3f4f6", color: done || active ? "white" : "#9ca3af" }}>
                          {done ? <CheckCircle size={15} weight="fill" /> : n}
                        </div>
                        <span className="text-[9px] font-semibold whitespace-nowrap" style={{ color: active ? "#8a9e60" : "#9ca3af" }}>{label}</span>
                      </div>
                      {i < ONBOARD_STEPS.length - 1 && <div className="flex-1 h-px mb-4 mx-1.5 transition-all" style={{ backgroundColor: done ? "#8a9e60" : "#e5e7eb" }} />}
                    </div>
                  );
                })}
              </div>
            </div>

            {/* Form Body */}
            <div className="flex-1 overflow-y-auto px-7 py-5">
              
              {onboardStep === 1 && (
                <div className="space-y-4">
                  <div className="bg-blue-50 border border-blue-100 rounded-lg p-3 mb-2">
                    <p className="text-xs text-blue-700 font-medium">A field must be linked to an existing vendor account on the platform.</p>
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Select Vendor *</label>
                    <select value={formData.vendorId} onChange={e => setField("vendorId", e.target.value)}
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] bg-white">
                      <option value="">Select a vendor...</option>
                      {Array.from(new Set(fields.map(f => f.vendor.name))).map(v => (
                        <option key={v} value={v}>{v}</option>
                      ))}
                    </select>
                  </div>
                </div>
              )}

              {onboardStep === 2 && (
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Field Name *</label>
                    <input value={formData.name} onChange={e => setField("name", e.target.value)}
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" placeholder="e.g. Turf Arena A" />
                  </div>
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">Sports Offered *</label>
                    <div className="flex flex-wrap gap-2">
                      {SPORTS_LIST.map(s => {
                        const sel = formData.sports.includes(s);
                        return <button key={s} onClick={() => toggleArr("sports", s)} className="px-3 py-1.5 rounded-lg text-xs font-medium border transition-colors" style={sel ? { backgroundColor: "#8a9e60", color: "white", borderColor: "transparent" } : { borderColor: "#e5e7eb", color: "#6b7280" }}>{s}</button>;
                      })}
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-3">
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Capacity</label>
                      <input type="number" value={formData.capacity} onChange={e => setField("capacity", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800" />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Size / Format</label>
                      <input value={formData.size} onChange={e => setField("size", e.target.value)} placeholder="e.g. 5-a-side" className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800" />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Surface Type</label>
                      <select value={formData.surface} onChange={e => setField("surface", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 bg-white">
                        {SURFACE_LIST.map(s => <option key={s}>{s}</option>)}
                      </select>
                    </div>
                  </div>
                </div>
              )}

              {onboardStep === 3 && (
                <div className="space-y-4">
                  <div>
                    <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Full Address *</label>
                    <input value={formData.address} onChange={e => setField("address", e.target.value)}
                      className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" placeholder="Street, Building, Landmark" />
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">City *</label>
                      <input value={formData.city} onChange={e => setField("city", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" placeholder="Mumbai" />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">State *</label>
                      <select value={formData.state} onChange={e => setField("state", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] bg-white">
                        <option value="">Select state</option>
                        {STATES_LIST.map(s => <option key={s}>{s}</option>)}
                      </select>
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Pincode</label>
                      <input value={formData.pincode} onChange={e => setField("pincode", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800" placeholder="400001" maxLength={6} />
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Location Zone</label>
                      <select value={formData.zone} onChange={e => setField("zone", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 bg-white">
                        <option>North Zone</option><option>South Zone</option><option>East Zone</option><option>West Zone</option><option>Central</option>
                      </select>
                    </div>
                    <div className="col-span-2">
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Google Maps Link</label>
                      <input value={formData.mapsLink} onChange={e => setField("mapsLink", e.target.value)} className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800" placeholder="Paste maps URL" />
                    </div>
                  </div>
                </div>
              )}

              {onboardStep === 4 && (
                <div className="space-y-5">
                  <div className="grid grid-cols-2 gap-3 pb-4 border-b border-gray-100">
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Standard Price / Hr *</label>
                      <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm">₹</span>
                        <input type="number" value={formData.pricePerHour} onChange={e => setField("pricePerHour", e.target.value)} className="w-full border border-gray-200 rounded-lg pl-7 pr-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Peak Price / Hr *</label>
                      <div className="relative">
                        <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500 text-sm">₹</span>
                        <input type="number" value={formData.peakPricePerHour} onChange={e => setField("peakPricePerHour", e.target.value)} className="w-full border border-gray-200 rounded-lg pl-7 pr-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
                      </div>
                    </div>
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Weekday Hours</label>
                      <div className="flex gap-2 items-center">
                        <input type="time" value={formData.weekdayFrom} onChange={e => setField("weekdayFrom", e.target.value)} className="flex-1 border border-gray-200 rounded-lg px-2 py-2 text-xs text-gray-800" />
                        <span className="text-gray-400 text-xs shrink-0">to</span>
                        <input type="time" value={formData.weekdayTo} onChange={e => setField("weekdayTo", e.target.value)} className="flex-1 border border-gray-200 rounded-lg px-2 py-2 text-xs text-gray-800" />
                      </div>
                    </div>
                    <div>
                      <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wider mb-1">Weekend Hours</label>
                      <div className="flex gap-2 items-center">
                        <input type="time" value={formData.weekendFrom} onChange={e => setField("weekendFrom", e.target.value)} className="flex-1 border border-gray-200 rounded-lg px-2 py-2 text-xs text-gray-800" />
                        <span className="text-gray-400 text-xs shrink-0">to</span>
                        <input type="time" value={formData.weekendTo} onChange={e => setField("weekendTo", e.target.value)} className="flex-1 border border-gray-200 rounded-lg px-2 py-2 text-xs text-gray-800" />
                      </div>
                    </div>
                  </div>
                </div>
              )}

              {onboardStep === 5 && (
                <div className="space-y-4">
                  <p className="text-sm font-medium text-gray-700">Select all amenities available at this specific field.</p>
                  <div className="flex flex-wrap gap-2.5 mt-4">
                    {FACILITIES_LIST.map(f => {
                      const sel = formData.facilities.includes(f);
                      return <button key={f} onClick={() => toggleArr("facilities", f)} className="px-3.5 py-2 rounded-lg text-xs font-medium border transition-colors" style={sel ? { backgroundColor: "#8a9e60", color: "white", borderColor: "transparent" } : { borderColor: "#e5e7eb", color: "#6b7280" }}>{f}</button>;
                    })}
                  </div>
                </div>
              )}

              {onboardStep === 6 && (
                <div className="space-y-6">
                  <div>
                    <h3 className="text-sm font-bold text-gray-800 mb-3">Upload KYC & Documents</h3>
                    <div className="space-y-2.5">
                      {KYC_DOCS_FIELD.map(({ key, label, hint }) => {
                        const uploaded = !!formData[key as FieldKycDocKey];
                        return (
                          <div key={key} className="border border-dashed border-gray-200 rounded-xl p-3.5 flex items-center justify-between hover:border-[#8a9e60] transition-colors group cursor-pointer">
                            <div><p className="text-xs font-semibold text-gray-700">{label}</p><p className="text-[10px] text-gray-400 mt-0.5">{hint}</p></div>
                            {uploaded ? (
                              <div className="flex items-center gap-1.5">
                                <span className="text-[10px] font-medium text-green-600 bg-green-50 px-2 py-0.5 rounded-full">Uploaded</span>
                                <button onClick={() => setField(key as keyof FormData, "")} className="text-gray-300 hover:text-red-400"><X size={12} /></button>
                              </div>
                            ) : (
                              <button onClick={() => setField(key as keyof FormData, "uploaded.pdf")}
                                className="flex items-center gap-1 text-[10px] font-medium text-[#8a9e60] border border-[#8a9e60] px-2.5 py-1 rounded-lg transition-colors group-hover:bg-[#8a9e60] group-hover:text-white">
                                <UploadSimple size={11} />Upload
                              </button>
                            )}
                          </div>
                        );
                      })}
                    </div>
                  </div>
                </div>
              )}

            </div>

            {/* Modal Footer */}
            <div className="px-7 py-4 border-t border-gray-100 flex items-center justify-between shrink-0 bg-gray-50/50">
              <button onClick={() => onboardStep > 1 ? setOnboardStep(s => s - 1) : closeOnboard()}
                className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-gray-500 border border-gray-200 rounded-lg hover:bg-white transition-colors bg-white">
                <ArrowLeft size={15} />{onboardStep === 1 ? "Cancel" : "Back"}
              </button>
              <button 
                onClick={() => {
                  if (onboardStep === 1 && !formData.vendorId) { alert("Please select a vendor first"); return; }
                  onboardStep < ONBOARD_STEPS.length ? setOnboardStep(s => s + 1) : closeOnboard()
                }}
                className="flex items-center gap-2 px-6 py-2 text-sm font-semibold text-white rounded-lg transition-opacity hover:opacity-90"
                style={{ backgroundColor: "#8a9e60" }}>
                {onboardStep === ONBOARD_STEPS.length ? "Submit & Onboard" : "Continue"}{onboardStep < ONBOARD_STEPS.length && <CaretRight size={15} />}
              </button>
            </div>
            
          </div>
        </div>
      )}

      {/* Detail panel overlay */}
      {selected && (
        <>
          <div className="fixed inset-0 bg-black/10 z-40" onClick={() => setSelected(null)} />
          <FieldDetailPanel field={selected} onClose={() => setSelected(null)} />
        </>
      )}
    </div>
  );
}

"use client";

import {
  BellRinging, PaperPlaneTilt, Users, Star, MapPin, SoccerBall,
  Lightning, Buildings, ArrowCounterClockwise, Trophy, Cloud,
  ClockCountdown, CalendarBlank, CheckCircle, X, ArrowUpRight,
  Eye, CaretDown, ChartLineUp, Clock, Trash,
} from "@phosphor-icons/react";
import { useState } from "react";

// ── Types ──────────────────────────────────────────────────────────────────────
type AudienceKey = "all" | "active" | "inactive" | "vip" | "city" | "sport";
type NotifStatus = "sent" | "scheduled" | "failed";

interface SentNotif {
  id: string; title: string; message: string;
  audience: string; reach: number; opened: number;
  openRate: number; sentAt: string; status: NotifStatus;
}

// ── Mock History ───────────────────────────────────────────────────────────────
const INIT_HISTORY: SentNotif[] = [
  { id: "PN-001", title: "Weekend Warriors Deal",            message: "Book this weekend and get 20% off on all turfs! Use code WEEKEND20 at checkout. Valid for 48 hours only.",                         audience: "Active Users",    reach: 834,  opened: 312, openRate: 37, sentAt: "Mar 20, 2026",          status: "sent"      },
  { id: "PN-002", title: "New Venue: Arena Hub Bengaluru",   message: "Exciting news! Arena Hub has just been onboarded. 3 premium turfs now available in Bengaluru — book your slot now.",              audience: "All Users",       reach: 1240, opened: 687, openRate: 55, sentAt: "Mar 18, 2026",          status: "sent"      },
  { id: "PN-003", title: "We Miss You!",                     message: "It's been a while since your last session. Come back and book a turf — your favourite sport is waiting for you!",                 audience: "Inactive Users",  reach: 312,  opened: 89,  openRate: 29, sentAt: "Mar 15, 2026",          status: "sent"      },
  { id: "PN-004", title: "VIP Early Access: Premium Fields", message: "As a Turfin VIP, you get 24-hour early access to new premium slots before they open to everyone else.",                           audience: "VIP Users",       reach: 47,   opened: 38,  openRate: 81, sentAt: "Mar 12, 2026",          status: "sent"      },
  { id: "PN-005", title: "IPL Season — Cricket Offer",       message: "Cricket season is here! Book cricket turfs at special rates all through April. Tap to explore venues near you.",                  audience: "Cricket Players", reach: 380,  opened: 171, openRate: 45, sentAt: "Mar 08, 2026",          status: "sent"      },
  { id: "PN-006", title: "Summer Slots Now Open",            message: "Beat the heat — book early morning slots for the best experience. Full summer schedule is now live on the app.",                  audience: "All Users",       reach: 1240, opened: 0,   openRate: 0,  sentAt: "Mar 25, 2026 10:00 AM", status: "scheduled" },
];

// ── Audience Config ────────────────────────────────────────────────────────────
const AUDIENCE_OPTIONS: {
  key: AudienceKey; label: string; icon: React.ElementType; reach: number; desc: string;
}[] = [
  { key: "all",      label: "All Users",      icon: Users,          reach: 1240, desc: "Every registered user"       },
  { key: "active",   label: "Active Users",   icon: CheckCircle,    reach: 834,  desc: "Booked in last 30 days"      },
  { key: "inactive", label: "Inactive Users", icon: ClockCountdown, reach: 312,  desc: "No activity for 30+ days"    },
  { key: "vip",      label: "VIP Users",      icon: Star,           reach: 47,   desc: "25+ bookings or ₹40k+ spent" },
  { key: "city",     label: "By City",        icon: MapPin,         reach: 0,    desc: "Target specific cities"      },
  { key: "sport",    label: "By Sport",       icon: SoccerBall,     reach: 0,    desc: "Target sport preference"     },
];

const CITIES: { name: string; count: number }[] = [
  { name: "Mumbai",    count: 380 }, { name: "Delhi",     count: 290 },
  { name: "Bangalore", count: 210 }, { name: "Pune",      count: 140 },
  { name: "Chennai",   count: 85  }, { name: "Hyderabad", count: 75  },
  { name: "Kolkata",   count: 60  },
];

const SPORTS: { name: string; count: number }[] = [
  { name: "Football",   count: 445 }, { name: "Cricket",    count: 380 },
  { name: "Badminton",  count: 210 }, { name: "Tennis",     count: 145 },
  { name: "Volleyball", count: 60  }, { name: "Basketball", count: 40  },
];

// ── Quick Templates ────────────────────────────────────────────────────────────
interface NotifTemplate {
  name: string; icon: React.ElementType; color: string;
  title: string; message: string; audience: AudienceKey;
}

const NOTIF_TEMPLATES: NotifTemplate[] = [
  { name: "Flash Sale",    icon: Lightning,            color: "text-amber-500 bg-amber-50",  audience: "all",      title: "Limited Time Offer!",          message: "Book any turf today and get 20% off! Use code TURFIN20 at checkout. Valid for 24 hours only." },
  { name: "New Venue",     icon: Buildings,            color: "text-blue-500 bg-blue-50",    audience: "active",   title: "New Venue Just Launched!",     message: "A new premium turf venue has just been onboarded near you. Check it out and secure your slot before it fills up!" },
  { name: "Re-engage",     icon: ArrowCounterClockwise,color: "text-purple-500 bg-purple-50",audience: "inactive", title: "We Miss You!",                 message: "It's been a while since your last booking. Come back and play — your favourite sport is waiting for you on Turfin!" },
  { name: "Tournament",    icon: Trophy,               color: "text-orange-500 bg-orange-50",audience: "all",      title: "Turfin League — Register Now!",message: "Our city-wide tournament is back! Register your team now and compete for the Turfin Cup. Slots are filling fast." },
  { name: "VIP Perk",      icon: Star,                 color: "text-yellow-500 bg-yellow-50",audience: "vip",      title: "VIP Exclusive: Early Access",  message: "As a Turfin VIP, you get 24-hour early access to new premium field slots before they open to everyone else." },
  { name: "Weather Alert", icon: Cloud,                color: "text-cyan-500 bg-cyan-50",    audience: "all",      title: "Weather Advisory",             message: "Due to forecasted rain, some outdoor fields may be affected today. Check the app for real-time availability updates." },
];

// ── Status Config ──────────────────────────────────────────────────────────────
const statusCfg: Record<NotifStatus, { cls: string; label: string }> = {
  sent:      { cls: "bg-green-50 text-green-700", label: "Sent"      },
  scheduled: { cls: "bg-blue-50 text-blue-600",   label: "Scheduled" },
  failed:    { cls: "bg-red-50 text-red-600",     label: "Failed"    },
};

// ── Main Component ─────────────────────────────────────────────────────────────
export default function NotificationsPage() {
  const [history, setHistory]           = useState<SentNotif[]>([...INIT_HISTORY]);

  // Compose form
  const [title, setTitle]               = useState("");
  const [message, setMessage]           = useState("");
  const [audience, setAudience]         = useState<AudienceKey>("all");
  const [cities, setCities]             = useState<string[]>([]);
  const [sports, setSports]             = useState<string[]>([]);
  const [scheduleType, setScheduleType] = useState<"now" | "later">("now");
  const [scheduleDate, setScheduleDate] = useState("");
  const [scheduleTime, setScheduleTime] = useState("");

  // UI state
  const [sending, setSending]           = useState(false);
  const [sentModal, setSentModal]       = useState<SentNotif | null>(null);
  const [expandedId, setExpandedId]     = useState<string | null>(null);
  const [historyFilter, setHistoryFilter] = useState<"all" | "sent" | "scheduled">("all");

  // ── Derived ────────────────────────────────────────────────────────────────
  const estimatedReach = (() => {
    if (audience === "city")  return cities.reduce((s, c) => s + (CITIES.find(x => x.name === c)?.count ?? 0), 0);
    if (audience === "sport") return sports.reduce((s, sp) => s + (SPORTS.find(x => x.name === sp)?.count ?? 0), 0);
    return AUDIENCE_OPTIONS.find(a => a.key === audience)?.reach ?? 0;
  })();

  const sentItems      = history.filter(n => n.status === "sent");
  const totalReach     = sentItems.reduce((s, n) => s + n.reach, 0);
  const avgOpenRate    = sentItems.length
    ? Math.round(sentItems.reduce((s, n) => s + n.openRate, 0) / sentItems.length) : 0;
  const scheduledCount = history.filter(n => n.status === "scheduled").length;

  // ── Handlers ───────────────────────────────────────────────────────────────
  function applyTemplate(t: NotifTemplate) {
    setTitle(t.title);
    setMessage(t.message);
    setAudience(t.audience);
    setCities([]);
    setSports([]);
  }

  function toggleCity(c: string) {
    setCities(prev => prev.includes(c) ? prev.filter(x => x !== c) : [...prev, c]);
  }

  function toggleSport(s: string) {
    setSports(prev => prev.includes(s) ? prev.filter(x => x !== s) : [...prev, s]);
  }

  function audienceLabel(): string {
    if (audience === "city")  return cities.length  ? cities.join(", ") + " Users"   : "Select cities";
    if (audience === "sport") return sports.length  ? sports.join(", ") + " Players" : "Select sports";
    return AUDIENCE_OPTIONS.find(a => a.key === audience)?.label ?? "All Users";
  }

  function handleSend() {
    if (!canSend) return;
    setSending(true);
    setTimeout(() => {
      const isScheduled = scheduleType === "later" && scheduleDate;
      const notif: SentNotif = {
        id:        `PN-${String(history.length + 1).padStart(3, "0")}`,
        title,
        message,
        audience:  audienceLabel(),
        reach:     estimatedReach,
        opened:    0,
        openRate:  0,
        sentAt:    isScheduled ? `${scheduleDate} ${scheduleTime}` : "Just now",
        status:    isScheduled ? "scheduled" : "sent",
      };
      setHistory(h => [notif, ...h]);
      setSending(false);
      setSentModal(notif);
      setTitle(""); setMessage(""); setAudience("all");
      setCities([]); setSports([]);
      setScheduleType("now"); setScheduleDate(""); setScheduleTime("");
    }, 1200);
  }

  function cancelScheduled(id: string) {
    setHistory(h => h.filter(n => n.id !== id));
    if (expandedId === id) setExpandedId(null);
  }

  function formatScheduledFor(): string {
    if (!scheduleDate) return "";
    const d = new Date(`${scheduleDate}T${scheduleTime || "00:00"}`);
    return d.toLocaleString("en-IN", {
      weekday: "short", month: "short", day: "numeric",
      hour: "2-digit", minute: "2-digit",
    });
  }

  const filteredHistory = historyFilter === "all"
    ? history
    : history.filter(n => n.status === historyFilter);

  const canSend =
    title.trim().length > 0 && message.trim().length > 0 &&
    (audience !== "city"  || cities.length > 0) &&
    (audience !== "sport" || sports.length > 0);

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div className="px-6 py-5 space-y-5">

      {/* ── Stats ── */}
      <div className="grid grid-cols-4 gap-4">
        {[
          { label: "Total Reach",          value: totalReach.toLocaleString(),    sub: "Cumulative push delivers",  icon: PaperPlaneTilt, color: "#8a9e60" },
          { label: "Avg Open Rate",         value: `${avgOpenRate}%`,              sub: "Across all campaigns",      icon: Eye,            color: "#6e8245" },
          { label: "Active Subscribers",    value: "1,240",                        sub: "Push-enabled users",        icon: BellRinging,    color: "#c4953a" },
          { label: "Scheduled",             value: String(scheduledCount),         sub: "Pending notifications",     icon: CalendarBlank,  color: "#6b7a96" },
        ].map(({ label, value, sub, icon: Icon, color }) => (
          <div key={label} className="bg-white rounded-xl p-4 border border-gray-100 shadow-sm">
            <div className="flex items-center justify-between mb-3">
              <span className="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">{label}</span>
              <div className="w-8 h-8 rounded-lg flex items-center justify-center" style={{ backgroundColor: color + "20" }}>
                <Icon size={16} weight="fill" style={{ color }} />
              </div>
            </div>
            <p className="text-2xl font-bold text-gray-800">{value}</p>
            <p className="text-[10px] text-gray-400 mt-1">{sub}</p>
          </div>
        ))}
      </div>

      {/* ── Main body ── */}
      <div className="flex gap-5 items-start">

        {/* ── Compose Panel ── */}
        <div className="flex-1 min-w-0">
          <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">

            {/* Header */}
            <div className="px-5 py-4 border-b border-gray-100 flex items-center gap-3"
              style={{ background: "linear-gradient(135deg,#8a9e60,#6e8245)" }}>
              <BellRinging size={18} className="text-white" weight="fill" />
              <div>
                <p className="text-white font-bold text-sm">Compose Push Notification</p>
                <p className="text-white/60 text-xs">Reach your users directly on their devices</p>
              </div>
            </div>

            <div className="p-5 space-y-5">

              {/* Title */}
              <div>
                <div className="flex items-center justify-between mb-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Title</label>
                  <span className={`text-[10px] font-medium ${title.length > 45 ? "text-red-500" : "text-gray-400"}`}>
                    {title.length}/50
                  </span>
                </div>
                <input
                  value={title}
                  onChange={e => { if (e.target.value.length <= 50) setTitle(e.target.value); }}
                  className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] transition-colors"
                  placeholder="e.g. Weekend Warriors Deal — 20% Off Today!"
                />
              </div>

              {/* Message */}
              <div>
                <div className="flex items-center justify-between mb-1.5">
                  <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider">Message</label>
                  <span className={`text-[10px] font-medium ${message.length > 135 ? "text-red-500" : "text-gray-400"}`}>
                    {message.length}/150
                  </span>
                </div>
                <textarea
                  value={message}
                  onChange={e => { if (e.target.value.length <= 150) setMessage(e.target.value); }}
                  rows={3}
                  className="w-full border border-gray-200 rounded-lg px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] transition-colors resize-none"
                  placeholder="Write a short, compelling message that drives action…"
                />
              </div>

              {/* Audience */}
              <div>
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider block mb-2">
                  Target Audience
                </label>
                <div className="grid grid-cols-3 gap-2">
                  {AUDIENCE_OPTIONS.map(opt => {
                    const Icon   = opt.icon;
                    const active = audience === opt.key;
                    return (
                      <button key={opt.key}
                        onClick={() => { setAudience(opt.key); setCities([]); setSports([]); }}
                        className={`flex items-center gap-2 p-2.5 rounded-xl border text-left transition-all
                          ${active ? "border-[#8a9e60] bg-[#8a9e60]/5" : "border-gray-100 hover:border-gray-200 bg-white"}`}>
                        <div className={`w-7 h-7 rounded-lg flex items-center justify-center shrink-0
                          ${active ? "bg-[#8a9e60]" : "bg-gray-100"}`}>
                          <Icon size={14} className={active ? "text-white" : "text-gray-400"}
                            weight={active ? "fill" : "regular"} />
                        </div>
                        <div>
                          <p className={`text-[11px] font-semibold leading-tight ${active ? "text-gray-900" : "text-gray-600"}`}>
                            {opt.label}
                          </p>
                          <p className="text-[9px] text-gray-400 leading-tight">
                            {opt.key !== "city" && opt.key !== "sport"
                              ? `~${opt.reach.toLocaleString()} users`
                              : opt.desc}
                          </p>
                        </div>
                      </button>
                    );
                  })}
                </div>

                {/* City picker */}
                {audience === "city" && (
                  <div className="mt-3 p-3 bg-gray-50 rounded-xl">
                    <p className="text-[10px] font-semibold text-gray-500 mb-2.5">Select Cities</p>
                    <div className="flex flex-wrap gap-2">
                      {CITIES.map(c => (
                        <button key={c.name} onClick={() => toggleCity(c.name)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all
                            ${cities.includes(c.name)
                              ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                              : "bg-white text-gray-600 border-gray-200 hover:border-[#8a9e60]"}`}>
                          {c.name} <span className="opacity-60">({c.count})</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {/* Sport picker */}
                {audience === "sport" && (
                  <div className="mt-3 p-3 bg-gray-50 rounded-xl">
                    <p className="text-[10px] font-semibold text-gray-500 mb-2.5">Select Sports</p>
                    <div className="flex flex-wrap gap-2">
                      {SPORTS.map(s => (
                        <button key={s.name} onClick={() => toggleSport(s.name)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all
                            ${sports.includes(s.name)
                              ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                              : "bg-white text-gray-600 border-gray-200 hover:border-[#8a9e60]"}`}>
                          {s.name} <span className="opacity-60">({s.count})</span>
                        </button>
                      ))}
                    </div>
                  </div>
                )}

                {/* Estimated reach */}
                <div className="mt-3 flex items-center gap-2 bg-gray-50 border border-gray-100 rounded-lg px-3 py-2.5">
                  <Users size={14} className="text-[#8a9e60] shrink-0" weight="fill" />
                  <p className="text-xs text-gray-600">
                    Estimated reach:{" "}
                    <span className="font-bold text-gray-900">{estimatedReach.toLocaleString()} users</span>
                  </p>
                </div>
              </div>

              {/* Schedule */}
              <div>
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider block mb-2">
                  Send Time
                </label>

                {/* Toggle */}
                <div className="flex gap-2 p-1 bg-gray-100 rounded-xl mb-3">
                  {(["now", "later"] as const).map(s => (
                    <button key={s} onClick={() => setScheduleType(s)}
                      className={`flex-1 flex items-center justify-center gap-1.5 py-2 rounded-lg text-xs font-semibold transition-all
                        ${scheduleType === s
                          ? "bg-white text-gray-900 shadow-sm"
                          : "text-gray-500 hover:text-gray-700"}`}>
                      {s === "now"
                        ? <><PaperPlaneTilt size={12} weight="fill" /> Send Now</>
                        : <><Clock size={12} weight="fill" /> Schedule Later</>}
                    </button>
                  ))}
                </div>

                {/* Date/time pickers */}
                {scheduleType === "later" && (
                  <div className="bg-gray-50 rounded-xl p-4 space-y-3 border border-gray-100">
                    <div className="flex gap-3">
                      {/* Date */}
                      <div className="flex-1">
                        <label className="text-[9px] font-bold text-gray-400 uppercase tracking-wider block mb-1.5">
                          Date
                        </label>
                        <div className="relative">
                          <CalendarBlank size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                          <input
                            type="date"
                            value={scheduleDate}
                            min={new Date().toISOString().split("T")[0]}
                            onChange={e => setScheduleDate(e.target.value)}
                            className="w-full border border-gray-200 bg-white rounded-lg pl-8 pr-3 py-2.5 text-sm text-gray-700 focus:outline-none focus:border-[#8a9e60] transition-colors"
                          />
                        </div>
                      </div>

                      {/* Time */}
                      <div className="flex-1">
                        <label className="text-[9px] font-bold text-gray-400 uppercase tracking-wider block mb-1.5">
                          Time
                        </label>
                        <div className="relative">
                          <Clock size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
                          <input
                            type="time"
                            value={scheduleTime}
                            onChange={e => setScheduleTime(e.target.value)}
                            className="w-full border border-gray-200 bg-white rounded-lg pl-8 pr-3 py-2.5 text-sm text-gray-700 focus:outline-none focus:border-[#8a9e60] transition-colors"
                          />
                        </div>
                      </div>
                    </div>

                    {/* Confirmation line */}
                    {scheduleDate ? (
                      <div className="flex items-center gap-2 bg-[#8a9e60]/8 border border-[#8a9e60]/20 rounded-lg px-3 py-2">
                        <CheckCircle size={13} className="text-[#8a9e60] shrink-0" weight="fill" />
                        <p className="text-xs text-gray-700">
                          Sends on <span className="font-semibold text-gray-900">{formatScheduledFor()}</span>
                        </p>
                      </div>
                    ) : (
                      <p className="text-[10px] text-gray-400 text-center">
                        Pick a date and time above to schedule your notification
                      </p>
                    )}
                  </div>
                )}
              </div>

              {/* Phone Preview */}
              <div>
                <label className="text-[10px] font-bold text-gray-400 uppercase tracking-wider block mb-2">
                  Device Preview
                </label>
                <div className="bg-gray-50 rounded-xl p-5 flex items-center gap-6">
                  {/* Phone mockup */}
                  <div className="shrink-0">
                    <div className="rounded-[24px] shadow-xl overflow-hidden"
                      style={{ width: 178, background: "#111827", padding: "10px 8px 14px" }}>
                      {/* Status bar */}
                      <div className="flex items-center justify-between px-2 mb-3">
                        <span className="text-white/50 text-[8px] font-semibold">9:41</span>
                        <div className="flex items-center gap-1">
                          <div className="w-2.5 h-1 bg-white/40 rounded-sm" />
                          <div className="w-1.5 h-1.5 rounded-full bg-white/40" />
                        </div>
                      </div>
                      {/* Notification banner */}
                      <div className="rounded-xl px-3 py-2.5 mx-0.5"
                        style={{ background: "rgba(255,255,255,0.10)", backdropFilter: "blur(12px)" }}>
                        <div className="flex items-center gap-1.5 mb-1.5">
                          <div className="w-4 h-4 rounded-md flex items-center justify-center shrink-0"
                            style={{ backgroundColor: "#8a9e60" }}>
                            <BellRinging size={9} className="text-white" weight="fill" />
                          </div>
                          <span className="text-white/60 text-[8px] font-bold uppercase tracking-wider">Turfin</span>
                          <span className="text-white/40 text-[8px] ml-auto">now</span>
                        </div>
                        <p className="text-white text-[9px] font-bold leading-tight mb-0.5 line-clamp-1">
                          {title || "Notification Title"}
                        </p>
                        <p className="text-white/55 text-[8px] leading-relaxed line-clamp-2">
                          {message || "Your notification message will appear here."}
                        </p>
                      </div>
                      {/* Home bar */}
                      <div className="flex justify-center mt-3">
                        <div className="w-12 h-1 rounded-full bg-white/20" />
                      </div>
                    </div>
                  </div>

                  {/* Description */}
                  <div className="flex-1 space-y-2">
                    <p className="text-sm font-semibold text-gray-800">Live Preview</p>
                    <p className="text-xs text-gray-500 leading-relaxed">
                      This is how your notification will appear on users&apos; lock screens and notification trays.
                    </p>
                    <p className="text-[10px] text-gray-400 leading-relaxed">
                      Notifications are delivered via FCM (Firebase Cloud Messaging) to all Turfin users with push permissions enabled.
                    </p>
                    <div className="flex gap-2 pt-1">
                      <span className="text-[9px] font-medium px-2 py-1 rounded bg-gray-100 text-gray-500">iOS</span>
                      <span className="text-[9px] font-medium px-2 py-1 rounded bg-gray-100 text-gray-500">Android</span>
                    </div>
                  </div>
                </div>
              </div>

              {/* Send button */}
              <button
                onClick={handleSend}
                disabled={!canSend || sending}
                className="w-full py-3 rounded-xl text-sm font-bold text-white flex items-center justify-center gap-2 transition-all disabled:opacity-40 disabled:cursor-not-allowed hover:opacity-90"
                style={{ backgroundColor: "#8a9e60" }}>
                {sending ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    Sending…
                  </>
                ) : (
                  <>
                    <PaperPlaneTilt size={15} weight="fill" />
                    {scheduleType === "now"
                      ? `Send to ${estimatedReach.toLocaleString()} Users`
                      : "Schedule Notification"}
                  </>
                )}
              </button>

            </div>
          </div>
        </div>

        {/* ── Right Panel ── */}
        <div className="w-72 shrink-0 space-y-4">

          {/* Quick Templates */}
          <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="px-4 py-3 border-b border-gray-100">
              <p className="text-xs font-bold text-gray-800">Quick Templates</p>
              <p className="text-[10px] text-gray-400 mt-0.5">Click to pre-fill the compose form</p>
            </div>
            <div className="p-3 space-y-1">
              {NOTIF_TEMPLATES.map(t => {
                const Icon = t.icon;
                return (
                  <button key={t.name} onClick={() => applyTemplate(t)}
                    className="w-full flex items-center gap-3 px-2.5 py-2.5 rounded-xl hover:bg-gray-50 transition-colors text-left group">
                    <div className={`w-8 h-8 rounded-lg flex items-center justify-center shrink-0 ${t.color}`}>
                      <Icon size={15} weight="fill" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-semibold text-gray-800">{t.name}</p>
                      <p className="text-[10px] text-gray-400 truncate">{t.title}</p>
                    </div>
                    <ArrowUpRight size={13} className="text-gray-300 group-hover:text-[#8a9e60] shrink-0 transition-colors" />
                  </button>
                );
              })}
            </div>
          </div>

          {/* Send History */}
          <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
            <div className="px-4 py-3 border-b border-gray-100">
              <div className="flex items-center justify-between mb-2">
                <p className="text-xs font-bold text-gray-800">Send History</p>
                <span className="text-[10px] text-gray-400">{filteredHistory.length} shown</span>
              </div>
              {/* Filter tabs */}
              <div className="flex gap-1 p-0.5 bg-gray-100 rounded-lg">
                {(["all", "sent", "scheduled"] as const).map(f => {
                  const count = f === "all" ? history.length : history.filter(n => n.status === f).length;
                  return (
                    <button key={f} onClick={() => setHistoryFilter(f)}
                      className={`flex-1 py-1 rounded-md text-[10px] font-semibold transition-all capitalize
                        ${historyFilter === f ? "bg-white text-gray-800 shadow-sm" : "text-gray-500 hover:text-gray-700"}`}>
                      {f} {count > 0 && <span className="opacity-60">({count})</span>}
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="divide-y divide-gray-50 max-h-[480px] overflow-y-auto">
              {filteredHistory.length === 0 && (
                <div className="px-4 py-8 text-center">
                  <p className="text-xs text-gray-400">No {historyFilter} notifications</p>
                </div>
              )}
              {filteredHistory.map(n => (
                <div key={n.id}>
                  <button
                    onClick={() => setExpandedId(expandedId === n.id ? null : n.id)}
                    className="w-full px-4 py-3 text-left hover:bg-gray-50 transition-colors">
                    <div className="flex items-start justify-between gap-2 mb-1">
                      <p className="text-xs font-semibold text-gray-800 leading-tight line-clamp-1 flex-1">
                        {n.title}
                      </p>
                      <span className={`text-[9px] font-bold px-1.5 py-0.5 rounded-full shrink-0 ${statusCfg[n.status].cls}`}>
                        {statusCfg[n.status].label}
                      </span>
                    </div>
                    <div className="flex items-center gap-2 text-[10px] text-gray-400 flex-wrap">
                      <span>{n.audience}</span>
                      {n.status === "sent" && (
                        <>
                          <span>·</span>
                          <span>{n.reach.toLocaleString()} sent</span>
                          <span>·</span>
                          <span className="font-medium" style={{ color: "#8a9e60" }}>{n.openRate}% opened</span>
                        </>
                      )}
                      {n.status === "scheduled" && (
                        <>
                          <span>·</span>
                          <span className="text-blue-500 font-medium">~{n.reach.toLocaleString()} users</span>
                        </>
                      )}
                    </div>
                    <div className="flex items-center gap-1 mt-1">
                      {n.status === "scheduled" && <Clock size={9} className="text-blue-400" weight="fill" />}
                      <p className="text-[9px] text-gray-300">{n.sentAt}</p>
                    </div>
                  </button>

                  {expandedId === n.id && (
                    <div className="px-4 pb-3 bg-gray-50 border-t border-gray-100">
                      <p className="text-[10px] text-gray-500 pt-2.5 leading-relaxed">{n.message}</p>

                      {n.status === "sent" && (
                        <div className="flex gap-4 mt-3 pt-3 border-t border-gray-100">
                          <div>
                            <p className="text-sm font-bold text-gray-800">{n.reach.toLocaleString()}</p>
                            <p className="text-[9px] text-gray-400">Delivered</p>
                          </div>
                          <div>
                            <p className="text-sm font-bold" style={{ color: "#8a9e60" }}>{n.opened.toLocaleString()}</p>
                            <p className="text-[9px] text-gray-400">Opened</p>
                          </div>
                          <div>
                            <p className="text-sm font-bold text-gray-800">{n.openRate}%</p>
                            <p className="text-[9px] text-gray-400">Open Rate</p>
                          </div>
                        </div>
                      )}

                      {n.status === "scheduled" && (
                        <div className="mt-3 pt-3 border-t border-gray-100 space-y-2">
                          <div className="flex items-center gap-2 bg-blue-50 rounded-lg px-3 py-2">
                            <Clock size={12} className="text-blue-500 shrink-0" weight="fill" />
                            <p className="text-[10px] text-blue-700 font-medium">
                              Scheduled to send at {n.sentAt}
                            </p>
                          </div>
                          <button
                            onClick={e => { e.stopPropagation(); cancelScheduled(n.id); }}
                            className="w-full flex items-center justify-center gap-1.5 py-1.5 rounded-lg border border-red-200 text-[10px] font-semibold text-red-500 hover:bg-red-50 transition-colors">
                            <Trash size={11} />
                            Cancel Scheduled Notification
                          </button>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>

        </div>
      </div>

      {/* ── Sent Success Modal ── */}
      {sentModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40">
          <div className="bg-white rounded-2xl shadow-2xl p-8 flex flex-col items-center gap-4 w-96">
            <div className="w-16 h-16 rounded-full flex items-center justify-center" style={{ backgroundColor: "#8a9e60" + "20" }}>
              {sentModal.status === "scheduled"
                ? <CalendarBlank size={32} style={{ color: "#8a9e60" }} weight="fill" />
                : <PaperPlaneTilt size={32} style={{ color: "#8a9e60" }} weight="fill" />}
            </div>
            <div className="text-center">
              <p className="text-base font-bold text-gray-900 mb-1">
                {sentModal.status === "scheduled" ? "Notification Scheduled!" : "Notification Sent!"}
              </p>
              <p className="text-sm text-gray-500">
                {sentModal.status === "scheduled"
                  ? `"${sentModal.title}" is scheduled for ${sentModal.sentAt}.`
                  : `"${sentModal.title}" was sent to ${sentModal.reach.toLocaleString()} users.`}
              </p>
            </div>
            <div className="w-full bg-gray-50 rounded-xl p-3 space-y-2">
              <div className="flex justify-between text-xs">
                <span className="text-gray-400">Audience</span>
                <span className="font-semibold text-gray-800">{sentModal.audience}</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-gray-400">Reach</span>
                <span className="font-semibold text-gray-800">{sentModal.reach.toLocaleString()} users</span>
              </div>
              <div className="flex justify-between text-xs">
                <span className="text-gray-400">Status</span>
                <span className={`font-bold px-2 py-0.5 rounded-full text-[10px] ${statusCfg[sentModal.status].cls}`}>
                  {statusCfg[sentModal.status].label}
                </span>
              </div>
            </div>
            <button
              onClick={() => setSentModal(null)}
              className="w-full py-2.5 rounded-xl text-sm font-semibold text-white hover:opacity-90 transition-opacity"
              style={{ backgroundColor: "#8a9e60" }}>
              Done
            </button>
          </div>
        </div>
      )}

    </div>
  );
}

"use client";

import {
  ShieldCheck, Users, Plus, PencilSimple, Trash, Lock,
  Crown, Check, X, Warning, UserPlus, Key,
} from "@phosphor-icons/react";
import { useState } from "react";

// ─── Types ────────────────────────────────────────────────────────────────────
type PermGroup   = Record<string, boolean>;
type Permissions = Record<string, PermGroup>;

interface Role {
  id: string;
  name: string;
  description: string;
  color: string;
  abbr: string;
  isSystem: boolean;
  permissions: Permissions;
}

interface PortalUser {
  id: string;
  name: string;
  email: string;
  avatar: string;
  roleId: string;
  lastActive: string;
  status: "active" | "inactive";
  joinedAt: string;
}

// ─── Permission Schema ────────────────────────────────────────────────────────
const PERM_SCHEMA: Record<string, { label: string; superOnly?: boolean; actions: string[] }> = {
  dashboard: { label: "Dashboard",     actions: ["View Overview", "View Alerts"] },
  bookings:  { label: "Bookings",      actions: ["View", "Edit", "Cancel Booking", "Issue Refund", "Export"] },
  fields:    { label: "Fields",        actions: ["View", "Approve New", "Edit Details", "Block Slots", "Suspend"] },
  users:     { label: "Users",         actions: ["View", "Edit Profile", "Suspend User", "Delete User"] },
  vendors:   { label: "Vendors",       actions: ["View", "Approve KYC", "Edit Details", "Suspend Vendor"] },
  analytics: { label: "Analytics",     actions: ["View Reports", "Export Data"] },
  settings:  { label: "Settings",      actions: ["View", "Edit"] },
  roles:     { label: "Roles & RBAC",  superOnly: true, actions: ["View", "Create", "Edit", "Delete", "Assign Users"] },
};

// ─── Roles Data ───────────────────────────────────────────────────────────────
const INITIAL_ROLES: Role[] = [
  {
    id: "super_admin", name: "Super Admin", abbr: "SA", color: "#dc2626", isSystem: true,
    description: "Full unrestricted access to all modules including RBAC management. Cannot be modified.",
    permissions: {
      dashboard: { "View Overview": true,  "View Alerts": true  },
      bookings:  { View: true, Edit: true, "Cancel Booking": true, "Issue Refund": true,  Export: true  },
      fields:    { View: true, "Approve New": true, "Edit Details": true, "Block Slots": true, Suspend: true  },
      users:     { View: true, "Edit Profile": true,  "Suspend User": true,  "Delete User": true  },
      vendors:   { View: true, "Approve KYC": true,  "Edit Details": true,  "Suspend Vendor": true  },
      analytics: { "View Reports": true,  "Export Data": true  },
      settings:  { View: true, Edit: true  },
      roles:     { View: true, Create: true, Edit: true, Delete: true, "Assign Users": true },
    },
  },
  {
    id: "admin", name: "Admin", abbr: "AD", color: "#2563eb", isSystem: true,
    description: "Full operational access across all modules. Cannot manage roles or edit platform settings.",
    permissions: {
      dashboard: { "View Overview": true,  "View Alerts": true  },
      bookings:  { View: true, Edit: true, "Cancel Booking": true, "Issue Refund": true,  Export: true  },
      fields:    { View: true, "Approve New": true, "Edit Details": true, "Block Slots": true, Suspend: true  },
