];

const CURRENT_USER_ID = "u1"; // Arjun Mehta — Super Admin (logged in)

// ─── Helpers ──────────────────────────────────────────────────────────────────
function permSummary(perms: Permissions) {
  const all     = Object.values(perms).flatMap(g => Object.values(g));
  const enabled = all.filter(Boolean).length;
  return { enabled, total: all.length };
}

// ─── Page ─────────────────────────────────────────────────────────────────────
export default function RolesPage() {
  const [roles, setRoles]           = useState<Role[]>(INITIAL_ROLES);
  const [users]                     = useState<PortalUser[]>(INITIAL_USERS);
  const [selectedId, setSelectedId] = useState<string>("super_admin");
  const [detailTab, setDetailTab]   = useState<"permissions" | "users">("permissions");
  const [editMode, setEditMode]     = useState(false);
  const [editedPerms, setEditedPerms]       = useState<Permissions | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [showNewRole, setShowNewRole]             = useState(false);
  const [newRoleName, setNewRoleName]             = useState("");
  const [newRoleDesc, setNewRoleDesc]             = useState("");

  const selected   = roles.find(r => r.id === selectedId)!;
  const roleUsers  = users.filter(u => u.roleId === selectedId);
  const activePerms = editMode && editedPerms ? editedPerms : selected.permissions;
  const { enabled: permCount, total: totalPerms } = permSummary(selected.permissions);

  function selectRole(id: string) {
    setSelectedId(id);
    setEditMode(false);
    setEditedPerms(null);
    setDetailTab("permissions");
  }

  function startEdit() {
    setEditedPerms(JSON.parse(JSON.stringify(selected.permissions)));
    setEditMode(true);
  }

  function cancelEdit() {
    setEditMode(false);
    setEditedPerms(null);
  }

  function saveEdit() {
    if (!editedPerms) return;
    setRoles(prev => prev.map(r => r.id === selectedId ? { ...r, permissions: editedPerms } : r));
    setEditMode(false);
    setEditedPerms(null);
  }

  function togglePerm(resource: string, action: string) {
    if (!editedPerms) return;
    setEditedPerms(prev => prev
      ? { ...prev, [resource]: { ...prev[resource], [action]: !prev[resource][action] } }
      : prev
    );
  }

  function deleteRole() {
    setRoles(prev => prev.filter(r => r.id !== selectedId));
    setSelectedId("super_admin");
    setShowDeleteConfirm(false);
  }

  function addRole() {
    if (!newRoleName.trim()) return;
    const id = newRoleName.toLowerCase().replace(/\s+/g, "_") + "_" + Date.now();
    const blank: Permissions = Object.fromEntries(
      Object.entries(PERM_SCHEMA).map(([k, { actions }]) => [k, Object.fromEntries(actions.map(a => [a, false]))])
    );
    setRoles(prev => [...prev, {
      id, name: newRoleName.trim(), description: newRoleDesc.trim() || "Custom role.",
      color: "#6b7280", abbr: newRoleName.trim().slice(0, 2).toUpperCase(),
      isSystem: false, permissions: blank,
    }]);
    setSelectedId(id);
    setNewRoleName("");
    setNewRoleDesc("");
    setShowNewRole(false);
    setDetailTab("permissions");
  }

  // Role color options
  const COLOR_OPTIONS = ["#dc2626","#2563eb","#8a9e60","#7c3aed","#0891b2","#d97706","#059669","#db2777","#6b7280"];

  return (
    <div className="h-full flex flex-col overflow-hidden">

      {/* ── Super Admin Guard Banner ── */}
      <div className="shrink-0 px-6 pt-5 pb-0">
        <div className="flex items-center gap-3 bg-red-50 border border-red-200 rounded-xl px-4 py-3">
          <div className="w-7 h-7 rounded-lg bg-red-100 flex items-center justify-center shrink-0">
            <Lock size={14} className="text-red-500" weight="fill" />
          </div>
          <div>
            <p className="text-xs font-bold text-red-700">Restricted — Super Admin Only</p>
            <p className="text-[11px] text-red-500 mt-0.5">
              This section controls who can see and do what across the entire portal. Misconfigured roles can expose sensitive operations.
            </p>
          </div>
          <div className="ml-auto shrink-0 text-right">
            <p className="text-[10px] text-red-400">Viewing as</p>
            <p className="text-xs font-bold text-red-600">Arjun Mehta (Super Admin)</p>
          </div>
        </div>
      </div>

      {/* ── Main layout ── */}
      <div className="flex-1 overflow-hidden flex gap-5 p-6 pt-4">

        {/* ── Left: Role list ── */}
        <div className="w-64 shrink-0 flex flex-col gap-3 overflow-y-auto">

          <div className="flex items-center justify-between">
            <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider">Portal Roles</p>
            <button
              onClick={() => setShowNewRole(true)}
              className="flex items-center gap-1 text-[11px] font-bold py-1.5 px-2.5 rounded-lg text-white hover:opacity-90 transition-opacity"
              style={{ backgroundColor: "#8a9e60" }}
            >
              <Plus size={12} weight="bold" /> New Role
            </button>
          </div>

          <div className="space-y-1.5">
            {roles.map(role => {
              const usersCount = users.filter(u => u.roleId === role.id).length;
              const { enabled, total } = permSummary(role.permissions);
              const isSelected = role.id === selectedId;
              return (
                <button
                  key={role.id}
                  onClick={() => selectRole(role.id)}
                  className={`w-full text-left rounded-xl p-3 transition-all border ${
                    isSelected
                      ? "bg-white shadow-sm border-gray-200"
                      : "border-transparent hover:bg-white hover:border-gray-100"
                  }`}
                >
                  <div className="flex items-center gap-2.5">
                    <div
                      className="w-8 h-8 rounded-xl flex items-center justify-center text-white text-[11px] font-bold shrink-0"
                      style={{ backgroundColor: role.color }}
                    >
                      {role.abbr}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <p className="text-xs font-bold text-gray-800 truncate">{role.name}</p>
                        {role.id === "super_admin" && (
                          <Crown size={11} weight="fill" className="text-amber-400 shrink-0" />
                        )}
                        {role.isSystem && (
                          <span className="text-[8px] bg-gray-100 text-gray-400 px-1 py-0.5 rounded font-bold uppercase leading-none shrink-0">SYS</span>
                        )}
                      </div>
                      <p className="text-[10px] text-gray-400">{usersCount} user{usersCount !== 1 ? "s" : ""}</p>
                    </div>
                  </div>

                  {isSelected && (
                    <div className="mt-2.5">
                      <div className="flex justify-between text-[9px] text-gray-400 mb-1">
                        <span>Permissions</span>
                        <span>{enabled}/{total}</span>
                      </div>
                      <div className="w-full bg-gray-100 rounded-full h-1">
                        <div
                          className="h-1 rounded-full transition-all"
                          style={{ width: `${(enabled / total) * 100}%`, backgroundColor: role.color }}
                        />
                      </div>
                    </div>
                  )}
                </button>
              );
            })}
          </div>

          {/* Users summary card */}
          <div className="bg-white rounded-xl border border-gray-100 p-3.5 mt-1">
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-2.5">All Portal Users</p>
            <div className="flex -space-x-1.5 mb-2.5">
              {users.slice(0, 7).map(u => (
                <div
                  key={u.id}
                  className="w-6 h-6 rounded-full border-2 border-white flex items-center justify-center text-white text-[8px] font-bold shrink-0"
                  style={{ backgroundColor: roles.find(r => r.id === u.roleId)?.color ?? "#8a9e60" }}
                  title={`${u.name} (${roles.find(r => r.id === u.roleId)?.name})`}
                >
                  {u.avatar}
                </div>
              ))}
              {users.length > 7 && (
                <div className="w-6 h-6 rounded-full border-2 border-white bg-gray-100 flex items-center justify-center text-[8px] font-bold text-gray-400">
                  +{users.length - 7}
                </div>
              )}
            </div>
            <p className="text-[11px] text-gray-500">
              {users.length} users across {roles.length} roles
            </p>
            <p className="text-[10px] text-gray-400 mt-0.5">
              {users.filter(u => u.status === "active").length} active · {users.filter(u => u.status === "inactive").length} inactive
            </p>
          </div>
        </div>

        {/* ── Right: Role detail ── */}
        <div className="flex-1 overflow-hidden flex flex-col bg-white rounded-2xl border border-gray-100 shadow-sm min-w-0">

          {/* Role header */}
          <div className="shrink-0 px-6 py-4 border-b border-gray-100 flex items-start justify-between gap-4">
            <div className="flex items-center gap-4 min-w-0">
              <div
                className="w-12 h-12 rounded-2xl flex items-center justify-center text-white text-sm font-bold shrink-0"
                style={{ backgroundColor: selected.color }}
              >
                {selected.abbr}
              </div>
              <div className="min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <h2 className="text-base font-bold text-gray-800">{selected.name}</h2>
                  {selected.id === "super_admin" && <Crown size={15} weight="fill" className="text-amber-400" />}
                  {selected.isSystem && (
                    <span className="text-[10px] bg-gray-100 text-gray-500 px-2 py-0.5 rounded font-bold uppercase">System Role</span>
                  )}
                </div>
                <p className="text-[11px] text-gray-400 mt-0.5 max-w-lg leading-relaxed">{selected.description}</p>
                <div className="flex items-center gap-4 mt-1.5 text-[11px] text-gray-400">
                  <span className="flex items-center gap-1">
                    <Users size={11} /> {roleUsers.length} user{roleUsers.length !== 1 ? "s" : ""}
                  </span>
                  <span className="flex items-center gap-1">
                    <Key size={11} /> {permCount}/{totalPerms} permissions enabled
                  </span>
                </div>
              </div>
            </div>

            {/* Action buttons */}
            <div className="flex items-center gap-2 shrink-0">
              {!editMode ? (
                <>
                  {selected.isSystem ? (
                    <span className="flex items-center gap-1.5 text-[11px] text-gray-400 bg-gray-50 px-3 py-2 rounded-xl border border-gray-100">
                      <Lock size={11} /> Cannot modify system role
                    </span>
                  ) : (
                    <>
                      <button
                        onClick={startEdit}
                        className="flex items-center gap-1.5 px-3 py-2 rounded-xl border border-gray-200 text-xs font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
                      >
                        <PencilSimple size={13} /> Edit Permissions
                      </button>
                      <button
                        onClick={() => setShowDeleteConfirm(true)}
                        className="flex items-center gap-1.5 px-3 py-2 rounded-xl bg-red-50 border border-red-100 text-xs font-semibold text-red-500 hover:bg-red-100 transition-colors"
                      >
                        <Trash size={13} /> Delete
                      </button>
                    </>
                  )}
                </>
              ) : (
                <>
                  <button
                    onClick={cancelEdit}
                    className="flex items-center gap-1.5 px-3 py-2 rounded-xl border border-gray-200 text-xs font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
                  >
                    <X size={13} /> Cancel
                  </button>
                  <button
                    onClick={saveEdit}
                    className="flex items-center gap-1.5 px-3 py-2 rounded-xl text-xs font-semibold text-white hover:opacity-90 transition-opacity"
                    style={{ backgroundColor: "#8a9e60" }}
                  >
                    <Check size={13} weight="bold" /> Save Changes
                  </button>
                </>
              )}
            </div>
          </div>

          {/* Tabs */}
          <div className="flex border-b border-gray-100 shrink-0 px-6">
            {(["permissions", "users"] as const).map(t => (
              <button
                key={t}
                onClick={() => setDetailTab(t)}
                className={`py-3 mr-6 text-xs font-bold capitalize border-b-2 transition-colors ${
                  detailTab === t
                    ? "border-[#8a9e60] text-[#8a9e60]"
                    : "border-transparent text-gray-400 hover:text-gray-600"
                }`}
              >
                {t === "users" ? `Assigned Users (${roleUsers.length})` : "Permissions"}
              </button>
            ))}
          </div>

          {/* Tab content */}
          <div className="flex-1 overflow-y-auto">

            {/* ── PERMISSIONS TAB ── */}
            {detailTab === "permissions" && (
              <div className="p-6 space-y-3">

                {editMode && (
                  <div className="flex items-start gap-2.5 bg-amber-50 border border-amber-200 rounded-xl px-4 py-3 mb-1">
                    <Warning size={14} className="text-amber-500 shrink-0 mt-0.5" />
                    <p className="text-xs text-amber-700">
                      Editing <span className="font-bold">{selected.name}</span>.
                      Changes apply immediately to all {roleUsers.length} user{roleUsers.length !== 1 ? "s" : ""} with this role.
                      Click permission tags to toggle them.
                    </p>
                  </div>
                )}

                {Object.entries(PERM_SCHEMA).map(([resource, { label, superOnly, actions }]) => {
                  const resourcePerms = activePerms[resource] ?? {};
                  const enabledCount  = actions.filter(a => resourcePerms[a]).length;

                  return (
                    <div
                      key={resource}
                      className={`rounded-xl border p-4 ${
                        superOnly
                          ? "border-red-100 bg-red-50/40"
                          : "border-gray-100 bg-gray-50/30"
                      }`}
                    >
                      <div className="flex items-center justify-between mb-3">
                        <div className="flex items-center gap-2">
                          <p className="text-xs font-bold text-gray-700">{label}</p>
                          {superOnly && (
                            <span className="text-[9px] bg-red-100 text-red-500 px-1.5 py-0.5 rounded font-bold uppercase leading-none">
                              Super Admin Only
                            </span>
                          )}
                        </div>
                        <span className="text-[10px] text-gray-400 font-medium">
                          {enabledCount}/{actions.length} enabled
                        </span>
                      </div>

                      <div className="flex flex-wrap gap-1.5">
                        {actions.map(action => {
                          const enabled   = !!resourcePerms[action];
                          const canToggle = editMode && !selected.isSystem;
                          return (
                            <button
                              key={action}
                              disabled={!canToggle}
                              onClick={() => togglePerm(resource, action)}
                              className={`flex items-center gap-1.5 px-2.5 py-1.5 rounded-lg text-[11px] font-semibold transition-all select-none ${
                                enabled
                                  ? "text-white"
                                  : canToggle
                                  ? "bg-white border border-dashed border-gray-300 text-gray-400 hover:border-gray-400 hover:text-gray-600"
                                  : "bg-white border border-gray-100 text-gray-300"
                              } ${canToggle ? "cursor-pointer hover:scale-105" : "cursor-default"}`}
                              style={enabled ? { backgroundColor: selected.color } : {}}
                            >
                              {enabled
                                ? <Check size={10} weight="bold" />
                                : <X size={10} className="opacity-50" />
                              }
                              {action}
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>
            )}

            {/* ── USERS TAB ── */}
            {detailTab === "users" && (
              <div className="p-6">
                <div className="flex items-center justify-between mb-4">
                  <p className="text-[11px] font-bold text-gray-400 uppercase tracking-wider">
                    {roleUsers.length} user{roleUsers.length !== 1 ? "s" : ""} assigned
                  </p>
                  <button
                    className="flex items-center gap-1.5 text-xs font-bold py-2 px-3 rounded-xl text-white hover:opacity-90 transition-opacity"
                    style={{ backgroundColor: "#8a9e60" }}
                  >
                    <UserPlus size={13} weight="bold" /> Assign User
                  </button>
                </div>

                {roleUsers.length === 0 ? (
                  <div className="py-20 text-center">
                    <Users size={36} className="text-gray-200 mx-auto mb-3" />
                    <p className="text-sm font-semibold text-gray-400">No users assigned yet</p>
                    <p className="text-xs text-gray-300 mt-1">Use &ldquo;Assign User&rdquo; to add someone to this role</p>
                  </div>
                ) : (
                  <div className="space-y-2">
                    {roleUsers.map(user => {
                      const isCurrentUser = user.id === CURRENT_USER_ID;
                      const roleInfo = roles.find(r => r.id === user.roleId);
                      return (
                        <div
                          key={user.id}
                          className={`flex items-center gap-4 p-4 rounded-xl border transition-colors ${
                            isCurrentUser
                              ? "border-[#8a9e60]/25 bg-[#8a9e60]/5"
                              : "border-gray-100 bg-gray-50/30 hover:bg-white hover:border-gray-200"
                          }`}
                        >
                          {/* Avatar */}
                          <div
                            className="w-9 h-9 rounded-full flex items-center justify-center text-white text-[11px] font-bold shrink-0"
                            style={{ backgroundColor: roleInfo?.color ?? "#8a9e60" }}
                          >
                            {user.avatar}
                          </div>

                          {/* Name + email */}
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 flex-wrap">
                              <p className="text-sm font-semibold text-gray-800">{user.name}</p>
                              {isCurrentUser && (
                                <span
                                  className="text-[9px] font-bold px-1.5 py-0.5 rounded text-white"
                                  style={{ backgroundColor: "#8a9e60" }}
                                >
                                  YOU
                                </span>
                              )}
                              <span className={`w-1.5 h-1.5 rounded-full ${user.status === "active" ? "bg-green-400" : "bg-gray-300"}`} />
                              <span className={`text-[10px] font-medium ${user.status === "active" ? "text-green-500" : "text-gray-400"}`}>
                                {user.status}
                              </span>
                            </div>
                            <p className="text-[11px] text-gray-400">{user.email}</p>
                          </div>

                          {/* Last active + joined */}
                          <div className="text-right shrink-0">
                            <p className="text-[11px] font-medium text-gray-600">{user.lastActive}</p>
                            <p className="text-[10px] text-gray-400">Joined {user.joinedAt}</p>
                          </div>

                          {/* Actions */}
                          {isCurrentUser ? (
                            <span title="Cannot change your own role" className="shrink-0">
                              <Lock size={14} className="text-gray-300" />
                            </span>
                          ) : (
                            <div className="flex items-center gap-1 shrink-0">
                              <button
                                className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors"
                                title="Change role"
                              >
                                <PencilSimple size={13} />
                              </button>
                              {selected.id !== "super_admin" && (
                                <button
                                  className="p-1.5 rounded-lg hover:bg-red-50 text-gray-400 hover:text-red-400 transition-colors"
                                  title="Remove from role"
                                >
                                  <X size={13} />
                                </button>
                              )}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </div>
                )}

                {/* All users not in this role */}
                {roleUsers.length < users.length && (
                  <div className="mt-6">
                    <p className="text-[11px] font-bold text-gray-300 uppercase tracking-wider mb-3">Other Portal Users</p>
                    <div className="space-y-1.5">
                      {users.filter(u => u.roleId !== selectedId).map(user => {
                        const roleInfo = roles.find(r => r.id === user.roleId);
                        return (
                          <div key={user.id} className="flex items-center gap-3 px-3 py-2 rounded-xl hover:bg-gray-50 transition-colors">
                            <div
                              className="w-7 h-7 rounded-full flex items-center justify-center text-white text-[9px] font-bold shrink-0"
                              style={{ backgroundColor: roleInfo?.color ?? "#8a9e60" }}
                            >
                              {user.avatar}
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-xs font-medium text-gray-600 truncate">{user.name}</p>
                              <p className="text-[10px] text-gray-400">{roleInfo?.name}</p>
                            </div>
                            <button
                              className="text-[10px] font-semibold px-2 py-1 rounded-lg border border-dashed border-gray-300 text-gray-400 hover:border-[#8a9e60] hover:text-[#8a9e60] transition-colors"
                            >
                              + Assign
                            </button>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </div>

      {/* ── Delete Confirm Modal ── */}
      {showDeleteConfirm && (
        <div className="fixed inset-0 bg-black/30 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl p-6 max-w-sm w-full">
            <div className="w-12 h-12 rounded-full bg-red-100 flex items-center justify-center mx-auto mb-4">
              <Trash size={22} className="text-red-500" />
            </div>
            <h3 className="text-base font-bold text-gray-800 text-center mb-2">Delete &ldquo;{selected.name}&rdquo;?</h3>
            <p className="text-xs text-gray-500 text-center leading-relaxed mb-2">
              This role will be permanently removed.
            </p>
            {roleUsers.length > 0 && (
              <div className="flex items-center gap-2 bg-red-50 border border-red-100 rounded-xl px-3 py-2 mb-4">
                <Warning size={13} className="text-red-400 shrink-0" />
                <p className="text-[11px] text-red-600 font-medium">
                  {roleUsers.length} user{roleUsers.length > 1 ? "s" : ""} will lose their role and may lose portal access.
                </p>
              </div>
            )}
            <div className="flex gap-3 mt-4">
              <button
                onClick={() => setShowDeleteConfirm(false)}
                className="flex-1 py-2.5 rounded-xl border border-gray-200 text-sm font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={deleteRole}
                className="flex-1 py-2.5 rounded-xl bg-red-500 text-white text-sm font-semibold hover:bg-red-600 transition-colors"
              >
                Delete Role
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── New Role Modal ── */}
      {showNewRole && (
        <div className="fixed inset-0 bg-black/30 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl p-6 max-w-sm w-full">
            <div className="flex items-center justify-between mb-5">
              <h3 className="text-base font-bold text-gray-800">Create New Role</h3>
              <button onClick={() => setShowNewRole(false)} className="text-gray-400 hover:text-gray-600">
                <X size={18} />
              </button>
            </div>

            <div className="space-y-3">
              <div>
                <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Role Name</label>
                <input
                  value={newRoleName}
                  onChange={e => setNewRoleName(e.target.value)}
                  placeholder="e.g. Field Inspector"
                  className="w-full border border-gray-200 rounded-xl px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] transition-colors"
                />
              </div>
              <div>
                <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Description</label>
                <textarea
                  value={newRoleDesc}
                  onChange={e => setNewRoleDesc(e.target.value)}
                  placeholder="Briefly describe what this role can do..."
                  rows={2}
                  className="w-full border border-gray-200 rounded-xl px-3 py-2.5 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] transition-colors resize-none"
                />
              </div>
              <div>
                <label className="block text-[11px] font-bold text-gray-400 uppercase tracking-wider mb-1.5">Badge Color</label>
                <div className="flex gap-2 flex-wrap">
                  {COLOR_OPTIONS.map(c => (
                    <button key={c} className="w-6 h-6 rounded-full border-2 border-white shadow-sm hover:scale-110 transition-transform" style={{ backgroundColor: c }} />
                  ))}
                </div>
              </div>
            </div>

            <p className="text-[10px] text-gray-400 mt-4 bg-gray-50 rounded-lg p-2.5">
              The new role will start with <span className="font-semibold">zero permissions</span>. You can configure them after creation.
            </p>

            <div className="flex gap-3 mt-4">
              <button
                onClick={() => setShowNewRole(false)}
                className="flex-1 py-2.5 rounded-xl border border-gray-200 text-sm font-semibold text-gray-600 hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={addRole}
                disabled={!newRoleName.trim()}
                className="flex-1 py-2.5 rounded-xl text-sm font-semibold text-white hover:opacity-90 transition-opacity disabled:opacity-40"
                style={{ backgroundColor: "#8a9e60" }}
              >
                Create Role
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import {
  Globe, CalendarBlank, CurrencyDollar, Bell, ShieldCheck,
  CheckCircle, XCircle, CaretDown, FloppyDisk, WarningCircle,
  Envelope, Phone,
} from "@phosphor-icons/react";
import { useState } from "react";

// ── Types ──────────────────────────────────────────────────────────────────────
type Section = "platform" | "bookings" | "payments" | "notifications" | "security";

interface Settings {
  // Platform
  platformName: string;
  supportEmail: string;
  supportPhone: string;
  currency: string;
  timezone: string;
  maintenanceMode: boolean;

  // Bookings
  minAdvanceNotice: string;
  maxAdvanceDays: string;
  cancellationWindow: string;
  autoCancelAfter: string;
  slotDurations: string[];
  allowPartialPayments: boolean;

  // Payments
  commissionRate: number;
  payoutCycle: string;
  minPayoutAmount: number;
  autoRefund: boolean;
  refundTime: string;
  paymentMethods: string[];

  // Notifications
  notifyDispute: boolean;
  notifyKyc: boolean;
  notifyNewVendor: boolean;
  dailyRevenueReport: boolean;
  dailyReportTime: string;
  weeklyDigest: boolean;

  // Security
  sessionTimeout: string;
  require2fa: boolean;
  maxLoginAttempts: number;
  auditRetention: string;
}

const DEFAULTS: Settings = {
  platformName: "Turfin",
  supportEmail: "support@turfinapp.in",
  supportPhone: "+91 98765 00000",
  currency: "INR",
  timezone: "Asia/Kolkata",
  maintenanceMode: false,

  minAdvanceNotice: "2hr",
  maxAdvanceDays: "30",
  cancellationWindow: "2hr",
  autoCancelAfter: "30min",
  slotDurations: ["1hr", "1.5hr", "2hr"],
  allowPartialPayments: false,

  commissionRate: 10,
  payoutCycle: "weekly",
  minPayoutAmount: 500,
  autoRefund: true,
  refundTime: "5-7days",
  paymentMethods: ["upi", "card", "wallet", "netbanking"],

  notifyDispute: true,
  notifyKyc: true,
  notifyNewVendor: true,
  dailyRevenueReport: true,
  dailyReportTime: "08:00",
  weeklyDigest: false,

  sessionTimeout: "4hr",
  require2fa: false,
  maxLoginAttempts: 5,
  auditRetention: "90days",
};

// ── Helpers ────────────────────────────────────────────────────────────────────
function Toggle({ on, onChange }: { on: boolean; onChange: (v: boolean) => void }) {
  return (
    <button onClick={() => onChange(!on)} className="relative shrink-0 w-10 h-5.5 rounded-full transition-colors"
      style={{ backgroundColor: on ? "#8a9e60" : "#d1d5db", height: 22, width: 40 }}>
      <span className="absolute top-0.5 rounded-full bg-white shadow-sm transition-all"
        style={{ width: 18, height: 18, left: on ? 20 : 2 }} />
    </button>
  );
}

function Select({ value, onChange, options }: {
  value: string; onChange: (v: string) => void;
  options: { value: string; label: string }[];
}) {
  return (
    <div className="relative">
      <select value={value} onChange={e => onChange(e.target.value)}
        className="w-full appearance-none border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-700 bg-white focus:outline-none focus:border-[#8a9e60] pr-8 transition-colors">
        {options.map(o => <option key={o.value} value={o.value}>{o.label}</option>)}
      </select>
      <CaretDown size={12} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
    </div>
  );
}

function Field({ label, desc, children }: { label: string; desc?: string; children: React.ReactNode }) {
  return (
    <div className="flex items-start justify-between gap-8 py-4 border-b border-gray-50 last:border-0">
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-gray-800">{label}</p>
        {desc && <p className="text-xs text-gray-400 mt-0.5 leading-relaxed">{desc}</p>}
      </div>
      <div className="shrink-0 w-56">{children}</div>
    </div>
  );
}

// ── Nav config ─────────────────────────────────────────────────────────────────
const SECTIONS: { key: Section; label: string; icon: React.ElementType; desc: string }[] = [
  { key: "platform",      label: "Platform",      icon: Globe,         desc: "Name, contact, locale"    },
  { key: "bookings",      label: "Bookings",      icon: CalendarBlank, desc: "Slots, cancellations"     },
  { key: "payments",      label: "Payments",      icon: CurrencyDollar,desc: "Commission, payouts"      },
  { key: "notifications", label: "Notifications", icon: Bell,          desc: "Admin alert preferences"  },
  { key: "security",      label: "Security",      icon: ShieldCheck,   desc: "Sessions, 2FA, audit logs"},
];

// ── Main Component ─────────────────────────────────────────────────────────────
export default function SettingsPage() {
  const [section, setSection]   = useState<Section>("platform");
  const [settings, setSettings] = useState<Settings>({ ...DEFAULTS });
  const [saved, setSaved]       = useState<Section | null>(null);
  const [dirty, setDirty]       = useState(false);

  function set<K extends keyof Settings>(key: K, value: Settings[K]) {
    setSettings(s => ({ ...s, [key]: value }));
    setDirty(true);
  }

  function toggleArr(key: "slotDurations" | "paymentMethods", val: string) {
    setSettings(s => ({
      ...s,
      [key]: s[key].includes(val) ? s[key].filter(x => x !== val) : [...s[key], val],
    }));
    setDirty(true);
  }

  function handleSave() {
    setSaved(section);
    setDirty(false);
    setTimeout(() => setSaved(null), 2500);
  }

  // ── Render ─────────────────────────────────────────────────────────────────
  return (
    <div className="flex h-full overflow-hidden" style={{ minHeight: "calc(100vh - 73px)" }}>

      {/* Left nav */}
      <aside className="w-56 shrink-0 border-r border-gray-100 bg-gray-50/60 p-3 overflow-y-auto">
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-wider px-2 mb-2">Settings</p>
        <nav className="space-y-0.5">
          {SECTIONS.map(s => {
            const Icon = s.icon;
            const active = section === s.key;
            return (
              <button key={s.key} onClick={() => setSection(s.key)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-left transition-all
                  ${active ? "bg-white shadow-sm text-gray-900" : "text-gray-500 hover:bg-white/60 hover:text-gray-700"}`}>
                <div className={`w-7 h-7 rounded-lg flex items-center justify-center shrink-0 transition-colors
                  ${active ? "bg-[#8a9e60]" : "bg-gray-100"}`}>
                  <Icon size={14} className={active ? "text-white" : "text-gray-400"} weight={active ? "fill" : "regular"} />
                </div>
                <div>
                  <p className="text-xs font-semibold leading-tight">{s.label}</p>
                  <p className="text-[9px] text-gray-400 leading-tight">{s.desc}</p>
                </div>
              </button>
            );
          })}
        </nav>
      </aside>

      {/* Content panel */}
      <div className="flex-1 overflow-y-auto">
        <div className="max-w-2xl p-6 space-y-1">

          {/* Section header */}
          {(() => {
            const s = SECTIONS.find(s => s.key === section)!;
            const Icon = s.icon;
            return (
              <div className="flex items-center gap-3 mb-5">
                <div className="w-9 h-9 rounded-xl flex items-center justify-center" style={{ backgroundColor: "#8a9e60" }}>
                  <Icon size={16} className="text-white" weight="fill" />
                </div>
                <div>
                  <h2 className="text-base font-bold text-gray-900">{s.label}</h2>
                  <p className="text-xs text-gray-400">{s.desc}</p>
                </div>
              </div>
            );
          })()}

          {/* ── Platform ── */}
          {section === "platform" && (
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm px-5 py-1">
              <Field label="Platform Name" desc="Shown across the admin panel and user-facing emails.">
                <input value={settings.platformName} onChange={e => set("platformName", e.target.value)}
                  className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
              </Field>
              <Field label="Support Email" desc="Users and vendors contact this address for help.">
                <div className="relative">
                  <Envelope size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input type="email" value={settings.supportEmail} onChange={e => set("supportEmail", e.target.value)}
                    className="w-full border border-gray-200 rounded-lg pl-8 pr-3 py-2 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
                </div>
              </Field>
              <Field label="Support Phone" desc="Displayed on booking receipts and cancellation notices.">
                <div className="relative">
                  <Phone size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                  <input type="tel" value={settings.supportPhone} onChange={e => set("supportPhone", e.target.value)}
                    className="w-full border border-gray-200 rounded-lg pl-8 pr-3 py-2 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
                </div>
              </Field>
              <Field label="Currency" desc="All pricing and payouts use this currency.">
                <Select value={settings.currency} onChange={v => set("currency", v)}
                  options={[{ value: "INR", label: "₹ Indian Rupee (INR)" }]} />
              </Field>
              <Field label="Timezone" desc="Affects booking timestamps, reports, and notifications.">
                <Select value={settings.timezone} onChange={v => set("timezone", v)}
                  options={[
                    { value: "Asia/Kolkata",  label: "IST — Asia/Kolkata (UTC+5:30)" },
                    { value: "Asia/Dubai",    label: "GST — Asia/Dubai (UTC+4)"      },
                    { value: "Asia/Singapore",label: "SGT — Asia/Singapore (UTC+8)"  },
                  ]} />
              </Field>
              <Field label="Maintenance Mode"
                desc="Blocks all new bookings and shows a maintenance notice in the app.">
                <div className="flex items-center gap-3">
                  <Toggle on={settings.maintenanceMode} onChange={v => set("maintenanceMode", v)} />
                  {settings.maintenanceMode && (
                    <span className="flex items-center gap-1 text-[10px] font-semibold text-orange-500">
                      <WarningCircle size={12} weight="fill" /> Active
                    </span>
                  )}
                </div>
              </Field>
            </div>
          )}

          {/* ── Bookings ── */}
          {section === "bookings" && (
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm px-5 py-1">
              <Field label="Minimum Advance Notice"
                desc="Users must book at least this far ahead of the slot time.">
                <Select value={settings.minAdvanceNotice} onChange={v => set("minAdvanceNotice", v)}
                  options={[
                    { value: "1hr",  label: "1 hour"   }, { value: "2hr",  label: "2 hours"  },
                    { value: "4hr",  label: "4 hours"  }, { value: "12hr", label: "12 hours" },
                    { value: "24hr", label: "24 hours" },
                  ]} />
              </Field>
              <Field label="Maximum Advance Booking"
                desc="How many days ahead users can book a slot.">
                <Select value={settings.maxAdvanceDays} onChange={v => set("maxAdvanceDays", v)}
                  options={[
                    { value: "7",  label: "7 days"  }, { value: "14", label: "14 days" },
                    { value: "30", label: "30 days" }, { value: "60", label: "60 days" },
                    { value: "90", label: "90 days" },
                  ]} />
              </Field>
              <Field label="Free Cancellation Window"
                desc="Users can cancel without penalty within this window before the slot.">
                <Select value={settings.cancellationWindow} onChange={v => set("cancellationWindow", v)}
                  options={[
                    { value: "1hr",  label: "1 hour before"  }, { value: "2hr",  label: "2 hours before" },
                    { value: "4hr",  label: "4 hours before" }, { value: "12hr", label: "12 hours before"},
                    { value: "24hr", label: "24 hours before"},
                  ]} />
              </Field>
              <Field label="Auto-cancel Unpaid Bookings"
                desc="Automatically cancel bookings where payment is not completed.">
                <Select value={settings.autoCancelAfter} onChange={v => set("autoCancelAfter", v)}
                  options={[
                    { value: "15min", label: "After 15 minutes" }, { value: "30min", label: "After 30 minutes" },
                    { value: "1hr",   label: "After 1 hour"     }, { value: "2hr",   label: "After 2 hours"   },
                  ]} />
              </Field>
              <Field label="Allowed Slot Durations"
                desc="The slot lengths vendors can offer when setting up fields.">
                <div className="flex flex-wrap gap-2">
                  {["30min","1hr","1.5hr","2hr","2.5hr","3hr"].map(d => (
                    <button key={d}
                      onClick={() => toggleArr("slotDurations", d)}
                      className={`px-3 py-1 rounded-lg text-xs font-semibold border transition-all
                        ${settings.slotDurations.includes(d)
                          ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                          : "bg-white text-gray-500 border-gray-200 hover:border-gray-400"}`}>
                      {d}
                    </button>
                  ))}
                </div>
              </Field>
              <Field label="Allow Partial Payments"
                desc="Let users pay a deposit at booking time and the balance later.">
                <Toggle on={settings.allowPartialPayments} onChange={v => set("allowPartialPayments", v)} />
              </Field>
            </div>
          )}

          {/* ── Payments ── */}
          {section === "payments" && (
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm px-5 py-1">
              <Field label="Platform Commission Rate"
                desc="Percentage Turfin deducts from each vendor booking before payout.">
                <div className="relative">
                  <input type="number" min={0} max={50} value={settings.commissionRate}
                    onChange={e => set("commissionRate", Number(e.target.value))}
                    className="w-full border border-gray-200 rounded-lg px-3 py-2 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60] pr-8" />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sm text-gray-400 font-semibold">%</span>
                </div>
              </Field>
              <Field label="Vendor Payout Cycle"
                desc="How frequently vendor earnings are transferred to their accounts.">
                <div className="flex gap-2">
                  {["weekly","biweekly","monthly"].map(c => (
                    <button key={c} onClick={() => set("payoutCycle", c)}
                      className={`flex-1 py-1.5 rounded-lg text-xs font-semibold border capitalize transition-all
                        ${settings.payoutCycle === c
                          ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                          : "bg-white text-gray-500 border-gray-200 hover:border-gray-400"}`}>
                      {c === "biweekly" ? "Bi-weekly" : c.charAt(0).toUpperCase() + c.slice(1)}
                    </button>
                  ))}
                </div>
              </Field>
              <Field label="Minimum Payout Amount"
                desc="Vendors must earn at least this amount before a payout is triggered.">
                <div className="relative">
                  <span className="absolute left-3 top-1/2 -translate-y-1/2 text-sm text-gray-400 font-semibold">₹</span>
                  <input type="number" min={0} value={settings.minPayoutAmount}
                    onChange={e => set("minPayoutAmount", Number(e.target.value))}
                    className="w-full border border-gray-200 rounded-lg pl-7 pr-3 py-2 text-sm text-gray-800 focus:outline-none focus:border-[#8a9e60]" />
                </div>
              </Field>
              <Field label="Auto-refund on Cancellation"
                desc="Automatically initiate refunds when a booking is cancelled within policy.">
                <Toggle on={settings.autoRefund} onChange={v => set("autoRefund", v)} />
              </Field>
              <Field label="Refund Processing Time"
                desc="Expected time for refunds to reflect in the user's payment source.">
                <Select value={settings.refundTime} onChange={v => set("refundTime", v)}
                  options={[
                    { value: "instant",   label: "Instant (Wallet)"     },
                    { value: "3-5days",   label: "3–5 business days"    },
                    { value: "5-7days",   label: "5–7 business days"    },
                    { value: "7-10days",  label: "7–10 business days"   },
                  ]} />
              </Field>
              <Field label="Accepted Payment Methods"
                desc="Payment options displayed at checkout in the Turfin app.">
                <div className="flex flex-wrap gap-2">
                  {[
                    { value: "upi",        label: "UPI"          },
                    { value: "card",       label: "Card"         },
                    { value: "wallet",     label: "Wallet"       },
                    { value: "netbanking", label: "Net Banking"  },
                  ].map(m => (
                    <button key={m.value} onClick={() => toggleArr("paymentMethods", m.value)}
                      className={`px-3 py-1 rounded-lg text-xs font-semibold border transition-all
                        ${settings.paymentMethods.includes(m.value)
                          ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                          : "bg-white text-gray-500 border-gray-200 hover:border-gray-400"}`}>
                      {m.label}
                    </button>
                  ))}
                </div>
              </Field>
            </div>
          )}

          {/* ── Notifications ── */}
          {section === "notifications" && (
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm px-5 py-1">
              <Field label="New Dispute Filed"
                desc="Send an email to admin when a user raises a booking dispute.">
                <Toggle on={settings.notifyDispute} onChange={v => set("notifyDispute", v)} />
              </Field>
              <Field label="Vendor KYC Submitted"
                desc="Alert admin when a vendor submits documents for KYC review.">
                <Toggle on={settings.notifyKyc} onChange={v => set("notifyKyc", v)} />
              </Field>
              <Field label="New Vendor Onboarded"
                desc="Notify admin when a new vendor completes onboarding and goes live.">
                <Toggle on={settings.notifyNewVendor} onChange={v => set("notifyNewVendor", v)} />
              </Field>
              <Field label="Daily Revenue Report"
                desc="Email a daily summary of bookings, revenue, and platform activity.">
                <div className="space-y-2">
                  <Toggle on={settings.dailyRevenueReport} onChange={v => set("dailyRevenueReport", v)} />
                  {settings.dailyRevenueReport && (
                    <div>
                      <p className="text-[9px] text-gray-400 mb-1">Send at</p>
                      <input type="time" value={settings.dailyReportTime}
                        onChange={e => set("dailyReportTime", e.target.value)}
                        className="w-full border border-gray-200 rounded-lg px-3 py-1.5 text-sm text-gray-700 focus:outline-none focus:border-[#8a9e60]" />
                    </div>
                  )}
                </div>
              </Field>
              <Field label="Weekly Analytics Digest"
                desc="Receive a weekly performance summary every Monday morning.">
                <Toggle on={settings.weeklyDigest} onChange={v => set("weeklyDigest", v)} />
              </Field>
              <div className="py-3">
                <p className="text-[10px] text-gray-400">All alerts are sent to <span className="font-semibold text-gray-600">{settings.supportEmail}</span></p>
              </div>
            </div>
          )}

          {/* ── Security ── */}
          {section === "security" && (
            <div className="bg-white rounded-2xl border border-gray-100 shadow-sm px-5 py-1">
              <Field label="Admin Session Timeout"
                desc="Automatically log out inactive admin sessions after this duration.">
                <Select value={settings.sessionTimeout} onChange={v => set("sessionTimeout", v)}
                  options={[
                    { value: "15min", label: "15 minutes" }, { value: "30min", label: "30 minutes" },
                    { value: "1hr",   label: "1 hour"     }, { value: "4hr",   label: "4 hours"    },
                    { value: "8hr",   label: "8 hours"    },
                  ]} />
              </Field>
              <Field label="Require 2FA for All Admins"
                desc="All admin accounts must set up two-factor authentication to log in.">
                <div className="flex items-center gap-3">
                  <Toggle on={settings.require2fa} onChange={v => set("require2fa", v)} />
                  {settings.require2fa && (
                    <span className="text-[10px] font-semibold text-[#8a9e60] flex items-center gap-1">
                      <CheckCircle size={12} weight="fill" /> Enforced
                    </span>
                  )}
                </div>
              </Field>
              <Field label="Max Login Attempts"
                desc="Lock an account temporarily after this many consecutive failed logins.">
                <div className="flex items-center gap-2">
                  {[3, 5, 10].map(n => (
                    <button key={n} onClick={() => set("maxLoginAttempts", n)}
                      className={`flex-1 py-1.5 rounded-lg text-xs font-bold border transition-all
                        ${settings.maxLoginAttempts === n
                          ? "bg-[#8a9e60] text-white border-[#8a9e60]"
                          : "bg-white text-gray-500 border-gray-200 hover:border-gray-400"}`}>
                      {n}
                    </button>
                  ))}
                </div>
              </Field>
              <Field label="Audit Log Retention"
                desc="How long admin action logs are stored before being purged.">
                <Select value={settings.auditRetention} onChange={v => set("auditRetention", v)}
                  options={[
                    { value: "30days",  label: "30 days"  }, { value: "60days",  label: "60 days"  },
                    { value: "90days",  label: "90 days"  }, { value: "180days", label: "180 days" },
                    { value: "365days", label: "1 year"   },
                  ]} />
              </Field>
              <div className="py-3 flex items-start gap-2">
                <WarningCircle size={14} className="text-amber-500 mt-0.5 shrink-0" weight="fill" />
                <p className="text-[10px] text-gray-400 leading-relaxed">
                  Security settings affect all admins platform-wide. Changes take effect immediately on the next login.
                </p>
              </div>
            </div>
          )}

          {/* ── Save bar ── */}
          <div className="flex items-center justify-between pt-4">
            <p className="text-xs text-gray-400">
              {saved === section
                ? <span className="flex items-center gap-1.5 text-[#8a9e60] font-medium"><CheckCircle size={13} weight="fill" /> Changes saved</span>
                : dirty ? "You have unsaved changes." : "No changes since last save."}
            </p>
            <button onClick={handleSave}
              className="flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-semibold text-white transition-opacity hover:opacity-90"
              style={{ backgroundColor: "#8a9e60" }}>
              <FloppyDisk size={14} weight="fill" />
              Save Changes
            </button>
          </div>

        </div>
      </div>
    </div>
  );
}

